/* ===== PERSISTENCIA ===== */
function normalize(){causas.forEach(c=>{
  c.pendientes=c.pendientes.map(p=>typeof p==='string'?{t:p,done:false}:p);
  c.documentos=(c.documentos||[]).map(d=>d.carpeta?d:({n:d.n,tipo:docTipo(d.n),fecha:'',usuario:'Rocío Luján',carpeta:inferCarpeta(d.n),relevancia:'tramite',visible:(d.v==='cli'),etiquetas:[],u:d.u||null,historial:[]}));
  if(c.actorPat===undefined)c.actorPat=(c.clienteEs==='pasiva')?'':(c.letrada||'');
  if(c.demandadoPat===undefined)c.demandadoPat=(c.clienteEs==='pasiva')?(c.letrada||''):'';
  if(c.clienteCalidad===undefined)c.clienteCalidad='';
  if(c.actorRol===undefined)c.actorRol='Actora';
  if(c.demandadoRol===undefined)c.demandadoRol='Demandado';
  if(c.cadTipo===undefined)c.cadTipo=inferCad(c);
  if(!c.honorarios){
    c.honorarios={ius:0,gastos:[],pagos:[]};
    if(c.id==='acosta')c.honorarios={ius:10,gastos:[{concepto:"Gastos iniciales de demanda",moneda:"ius",monto:3,pagado:false},{concepto:"Boleta Colegio de Abogados",moneda:"ars",monto:42000,pagado:false}],pagos:[]};
  }
});}
function seedCausas(){causas=JSON.parse(JSON.stringify(CAUSAS));normalize();}
/* ===== Detección de cambios por causa (v46) =====
   Evita que dos personas del estudio se pisen: cada navegador guarda una
   "huella" de cómo estaba cada causa al cargarla. Al guardar, solo se marcan
   como modificadas las que cambiaron ACÁ. El servidor deja intactas las demás,
   así el trabajo de un colega no se sobrescribe.
   Si la huella no se puede calcular, la causa se marca como modificada: ante
   la duda, se guarda (nunca se pierde un cambio). */
let __hashCausas={};
function hashCausa(c){
  try{
    const s=JSON.stringify(c);
    let h=0;
    for(let i=0;i<s.length;i++){h=((h<<5)-h+s.charCodeAt(i))|0;}
    return s.length+':'+h;
  }catch(e){return null;}
}
function marcarCausasGuardadas(arr){
  try{
    __hashCausas={};
    (arr||[]).forEach(function(c){const h=hashCausa(c);if(h!==null)__hashCausas[c.id]=h;});
  }catch(e){__hashCausas={};}
}
async function loadState(){
  try{if(window.storage){const r=await window.storage.get(STORE);if(r&&r.value)return JSON.parse(r.value);}}catch(e){}
  try{if(typeof localStorage!=='undefined'){const v=localStorage.getItem(STORE);if(v)return JSON.parse(v);}}catch(e){}
  return null;
}
async function saveState(){
  // Separar causas PROPIAS (van al bloque del estudio) de las COMPARTIDAS por
  // otro estudio (se guardan en su causa de origen, sin tocar mi estudio).
  const propias=causas.filter(c=>!c._compartida);
  const data=JSON.stringify(propias);
  /* 1) Respaldo en el dispositivo SIEMPRE primero: pase lo que pase, no se pierde acá. */
  try{if(typeof localStorage!=='undefined')localStorage.setItem(STORE,data);}catch(e){}
  /* 2) Guardado en el servidor. Se marca qué causas cambiaron REALMENTE en
        este dispositivo, para que el servidor no pise el trabajo de un colega
        en las causas que acá no se tocaron. */
  const paraServidor=JSON.stringify(propias.map(function(c){
    const h=hashCausa(c);
    const anterior=__hashCausas[c.id];
    const cambiada=(anterior===undefined)||(h===null)||(h!==anterior);
    return Object.assign({},c,{_mod:cambiada});
  }));
  try{
    if(window.storage){await window.storage.set(STORE,paraServidor);marcarCausasGuardadas(propias);syncOk();}
  }catch(e){syncFallo(paraServidor,e);}
  const comp=causas.filter(c=>c._compartida&&c._permiso==='edicion');
  for(const c of comp){
    try{
      const r=await fetch('/api/compartir/causa/'+encodeURIComponent(c.id),{method:'PUT',credentials:'same-origin',headers:{'Content-Type':'application/json'},body:JSON.stringify({causa:c})});
      if(!r.ok)syncAviso('warn','No se pudo guardar en el servidor un cambio de una causa compartida.');
    }catch(e){syncAviso('warn','Sin conexión: un cambio de una causa compartida no se guardó en el servidor.');}
  }
}
/* ===== Guardado confiable: aviso visible + reintento automático (v46) ===== */
let __syncPend=null,__syncTimer=null,__syncFallos=0;
function syncAvisoEl(){let el=document.getElementById('syncAviso');if(!el){el=document.createElement('div');el.id='syncAviso';document.body.appendChild(el);}return el;}
function syncAviso(tipo,msg,conBoton){
  const el=syncAvisoEl();el.className=tipo||'';
  el.innerHTML='<span>'+esc(msg||'')+'</span>'+(conBoton?'<button onclick="reintentarGuardado()">Reintentar ahora</button>':'');
  if(tipo==='ok')setTimeout(()=>{const e2=document.getElementById('syncAviso');if(e2&&e2.className==='ok')e2.className='';},2500);
}
function syncOk(){
  const habia=!!__syncPend;
  __syncPend=null;__syncFallos=0;
  if(__syncTimer){clearTimeout(__syncTimer);__syncTimer=null;}
  if(habia)syncAviso('ok','✓ Listo: los cambios quedaron guardados en el servidor.');
  else{const el=document.getElementById('syncAviso');if(el&&el.className!=='ok')el.className='';}
}
function syncFallo(data,e){
  __syncPend=data;__syncFallos++;
  const sinSesion=e&&(e.code===401||/NO_SESION/i.test(e.message||''));
  if(sinSesion)syncAviso('err','Tu sesión venció: los cambios NO se guardaron en el servidor. Iniciá sesión de nuevo (tus datos siguen en este dispositivo).',true);
  else syncAviso('err','No se pudo guardar en el servidor (guardado en este dispositivo). Reintentando…',true);
  programarReintento();
}
function programarReintento(){
  if(__syncTimer||!__syncPend)return;
  const espera=Math.min(30000,2000*Math.pow(2,Math.min(4,__syncFallos-1)));
  __syncTimer=setTimeout(async function(){
    __syncTimer=null;if(!__syncPend)return;
    try{if(window.storage){await window.storage.set(STORE,__syncPend);syncOk();}}catch(e){syncFallo(__syncPend,e);}
  },espera);
}
async function reintentarGuardado(){
  if(!__syncPend){syncOk();return;}
  syncAviso('warn','Reintentando guardar…');
  try{if(window.storage){await window.storage.set(STORE,__syncPend);syncOk();}}catch(e){syncFallo(__syncPend,e);}
}
if(typeof window!=='undefined'){window.addEventListener('online',function(){if(__syncPend){__syncFallos=0;programarReintento();}});}
function persist(){saveState();}
let misCompartidas={}; // uuid -> cantidad de externos con acceso (causas que YO compartí)
/* Trae las causas que OTROS estudios me compartieron y las agrega (etiquetadas). */
async function cargarCompartidas(){
  try{
    const r=await fetch('/api/compartir/conmigo',{credentials:'same-origin'});
    const j=await r.json();
    if(j&&j.ok&&Array.isArray(j.data)&&j.data.length){
      j.data.forEach(sc=>{
        sc._compartida=true;
        // Si hay una causa local con el mismo id (p.ej. dato de ejemplo), la
        // reemplaza por la compartida real; si no, la agrega.
        const i=causas.findIndex(c=>c.id===sc.id);
        if(i>=0)causas.splice(i,1,sc); else causas.push(sc);
      });
      normalize();
    }
  }catch(e){}
  // Marcar cuáles de MIS causas están compartidas con externos (para el cartel).
  try{
    const r2=await fetch('/api/compartir/mias',{credentials:'same-origin'});
    const j2=await r2.json();
    misCompartidas={};
    if(j2&&j2.ok&&Array.isArray(j2.data))j2.data.forEach(x=>{misCompartidas[x.causa_uuid]=+x.n||1;});
  }catch(e){}
}
