function renderCaducidadMain(){
  const rows=[];
  causas.forEach(c=>{const r=calcCaducidad(c);if(r.nocaduca)return;rows.push({c,r});});
  const rank=x=>x.r.pausa?70000:(x.r.sinImpulso?80000:(x.r.diasRest==null?90000:x.r.diasRest));
  rows.sort((a,b)=>rank(a)-rank(b));
  const rowsHtml=rows.length?rows.map(({c,r})=>{
    let cls,dias,tag;
    if(r.pausa){cls='pausa';dias='En pausa';tag='a despacho';}
    else if(r.sinImpulso){cls='sininfo';dias='Sin datos';tag='marcá el impulso';}
    else{cls=r.nivel;dias=(r.diasRest<0?('Vencido '+Math.abs(r.diasRest)+'d'):(r.diasRest+' días'));tag=(r.diasRest<0?'caducó el plazo':'vence '+dmyCad(r.venc));}
    const meta=((CAD_TIPOS[r.tipo]||{}).l||'').split(' — ')[0];
    const lado=c.clienteEs==='pasiva'?'Demandado · podés acusarla':'Actor · tu carga';
    return `<button class="cadp-row ${cls}" onclick="abrirFicha('${c.id}')"><div class="cadp-bar"></div><div class="cadp-main"><div class="cadp-car">${esc(c.caratula)}</div><div class="cadp-meta">${esc(meta)} · ${lado}</div></div><div class="cadp-right"><div class="cadp-dias">${dias}</div><div class="cadp-tag">${esc(tag)}</div></div></button>`;
  }).join(''):`<div class="vacio">Ninguna causa con plazo de caducidad activo. Las sucesiones, voluntarios y familia no caducan.</div>`;
  document.getElementById('app').innerHTML=`<div class="tool-wrap wide">
    <div class="page-tit">Caducidad de instancia</div>
    <div class="page-sub">Causas con plazo activo, ordenadas por urgencia. No incluye sucesiones, voluntarios, ejecución de sentencia ni familia (no caducan). Tocá una para abrir su ficha.</div>
    <div class="cad-warn">⚠ Cálculos orientativos. Verificá cada plazo en el expediente y en la norma aplicable antes de actuar.</div>
    ${rowsHtml}
    <div class="calc-note" style="margin-top:16px">CPCyC de Catamarca (Ley 2339, arts. 310-318). No descuenta ferias; avisa con margen.</div></div>`;
}
