function inicioStats(){
  const tot=causas.length,ct=causas.filter(c=>c.estado==="tramite").length,cp=causas.filter(c=>c.estado==="preparacion").length,cs=causas.filter(c=>c.estado==="suspenso").length,cf=causas.filter(c=>c.estado==="finalizada").length;
  const tISO=new Date().toISOString().slice(0,10);
  const audHoy=audiencias.filter(a=>a.fecha===tISO).length;
  const vencPlazo=causas.filter(c=>{const r=calcCaducidad(c);return !r.nocaduca&&!r.pausa&&r.diasRest!=null&&r.diasRest<=45;}).length;
  const escritos=causas.reduce((s,c)=>s+c.pendientes.filter(p=>!p.done).length,0);
  let honPesos=0;causas.forEach(c=>{const hh=c.honorarios||{};const pag=(hh.pagos||[]).filter(p=>p.confirmado!==false).reduce((s,p)=>s+(+p.ius||0),0);const saldo=(+hh.ius||0)-pag;if(saldo>0)honPesos+=saldo*(+config.valorIUS||0);});
  return {tot,ct,cp,cs,cf,audHoy,vencPlazo,escritos,honPesos};
}
