      if(j.data&&j.data.clave_temporal){msg.style.color='#067647';msg.innerHTML='✓ Cuenta creada. <b>Clave temporal: '+esc(j.data.clave_temporal)+'</b><br>Pasásela al cliente; la cambia en su primer ingreso.';}
      else{msg.style.color='#067647';msg.textContent='✓ El cliente ya tenía cuenta; se le sumó esta causa.';}
      ov.querySelector('#acEmail').value='';lista();
