async function addPago(id){const c=get(id);const f=isoToDMY(document.getElementById('pg_fecha').value);const ius=+document.getElementById('pg_ius').value;const nota=document.getElementById('pg_nota').value.trim();const comp=document.getElementById('pg_comp').value.trim();const fileEl=document.getElementById('pg_file');const file=fileEl&&fileEl.files&&fileEl.files[0];if(!ius||ius<=0){document.getElementById('pg_ius').focus();return;}let compArch=null;if(file){try{const fd=new FormData();fd.append('file',file);fd.append('causa_id',c.id);fd.append('nombre','Comprobante de pago');fd.append('carpeta','prueba');const r=await fetch('/api/archivos',{method:'POST',credentials:'same-origin',body:fd});const j=await r.json();if(j&&j.ok&&j.data)compArch=j.data.id;}catch(e){}}c.honorarios.pagos.unshift({fecha:f,ius,nota,comp,compArch,confirmado:true});persist();renderFicha();}
function confirmarPago(id,i){const c=get(id);if(!c||!c.honorarios||!c.honorarios.pagos[i])return;if(!confirm('¿Confirmar que recibiste este pago? Se sumará a lo cobrado.'))return;c.honorarios.pagos[i].confirmado=true;c.honorarios.pagos[i].confirmadoEn=new Date().toISOString();persist();renderFicha();}
async function informarPagoCliente(causaId){
  const iusEl=document.getElementById('cli_pg_ius');const fileEl=document.getElementById('cli_pg_file');
  const ius=+(iusEl&&iusEl.value);if(!ius||ius<=0){alert('Ingresá el monto en IUS que transferiste.');return;}
  const fd=new FormData();fd.append('causa_uuid',causaId);fd.append('ius',ius);if(fileEl&&fileEl.files&&fileEl.files[0])fd.append('file',fileEl.files[0]);
  try{const r=await fetch('/api/acceso/pago',{method:'POST',credentials:'same-origin',body:fd});const j=await r.json();if(!j||j.ok===false)throw new Error((j&&j.error)||'Error');
    alert('¡Listo! Informaste tu pago. El estudio lo va a revisar y confirmar.');location.reload();
  }catch(e){alert('No se pudo informar el pago: '+e.message);}
}
async function delPago(id,i){const c=get(id);const p=c.honorarios.pagos[i];if(!p)return;
  const msg=p.recibo?('⚠️ Este pago tiene el RECIBO N° '+String(p.recibo.num).padStart(4,'0')+' emitido.\n\nAl eliminarlo se ANULA el recibo y se quita del Libro de Recibos. Esta acción no se puede deshacer.\n\n¿Continuar?'):'¿Eliminar este pago? Esta acción no se puede deshacer.';
  if(!confirm(msg))return;
  if(p.recibo&&p.recibo.serverId){try{await fetch('/api/recibos/'+p.recibo.serverId,{method:'DELETE',credentials:'same-origin'});}catch(e){}}
  c.honorarios.pagos.splice(i,1);persist();renderFicha();}
function addGasto(id){const c=get(id);const concepto=document.getElementById('gs_concepto').value.trim();const moneda=document.getElementById('gs_moneda').value;const monto=+document.getElementById('gs_monto').value;const comp=document.getElementById('gs_comp').value.trim();if(!concepto||!monto){return;}c.honorarios.gastos.push({concepto,moneda,monto,comp,pagado:false});persist();renderFicha();}
function delGasto(id,i){const c=get(id);c.honorarios.gastos.splice(i,1);persist();renderFicha();}
function toggleGasto(id,i){const c=get(id);c.honorarios.gastos[i].pagado=!c.honorarios.gastos[i].pagado;persist();renderFicha();}
function isoToDMY(iso){if(!iso)return hoy();const p=iso.split('-');return p.length===3?(p[2]+'/'+p[1]+'/'+p[0]):iso;}
