let calcSt={open:false,mode:'fija',q:'',sel:null,base:'',tipo:'conocimiento',otroMin:20,last:null,applied:null};
const fjus=n=>{n=Math.round((+n||0)*100)/100;if(Number.isInteger(n))return String(n);let s=n.toFixed(2).replace(/0+$/,'').replace(/\.$/,'');return s.replace('.',',');};
function toggleCalc(force){const open=(typeof force==='boolean')?force:!calcSt.open;calcSt.open=open;document.body.classList.toggle('calc-open',open);if(open)renderSide();}
function setCalcMode(m){calcSt.mode=m;calcSt.applied=null;renderCalc();}
function calcQinput(v){calcSt.q=v;const lst=document.getElementById('calcList');if(lst)lst.innerHTML=calcListHtml();}
function calcListHtml(){const q=(calcSt.q||'').toLowerCase().trim();let out='';let grp='';const items=ARANCEL_FIJOS.map((it,i)=>({it,i})).filter(o=>!q||(o.it.l+' '+o.it.g).toLowerCase().includes(q));if(!items.length)return '<div class="vacio" style="padding:14px 2px">Sin coincidencias.</div>';items.forEach(o=>{if(o.it.g!==grp){grp=o.it.g;out+='<div class="calc-grp">'+esc(grp)+'</div>';}out+='<button class="calc-it '+(calcSt.sel===o.i?'sel':'')+'" onclick="calcSelFija('+o.i+')"><span>'+esc(o.it.l)+'</span><span class="cj">'+fjus(o.it.jus)+' JUS</span></button>';});return out;}
function calcSelFija(i){calcSt.sel=i;calcSt.applied=null;renderCalc();}
function tramo25(j){if(j<=30)return{r:"0 – 30 JUS",min:19,max:25};if(j<=90)return{r:"31 – 90 JUS",min:18,max:24};if(j<=180)return{r:"91 – 180 JUS",min:17,max:23};if(j<=300)return{r:"181 – 300 JUS",min:16,max:22};if(j<=900)return{r:"301 – 900 JUS",min:15,max:21};if(j<=1500)return{r:"901 – 1500 JUS",min:14,max:20};return{r:"1501 JUS en adelante",min:13,max:19};}
function calcEco(){const vIus=+config.valorIUS||0;const raw=(calcSt.base||'').toString().replace(/[^\d.,]/g,'').replace(/\./g,'').replace(',','.');const base=+raw||0;const tEl=document.getElementById('calc_tipo');if(tEl)calcSt.tipo=tEl.value;const omEl=document.getElementById('calc_otromin');if(omEl)calcSt.otroMin=omEl.value;if(!vIus){calcSt.last={err:'sinius'};renderCalc();return;}if(!base||base<=0){calcSt.last={err:'sinbase'};renderCalc();return;}const baseJUS=base/vIus;const t=tramo25(baseJUS);const honMinJUS=baseJUS*t.min/100;const honMaxJUS=baseJUS*t.max/100;const legalMin=calcSt.tipo==='conocimiento'?20:(calcSt.tipo==='ejecucion'?10:(+calcSt.otroMin||0));let warn=null,effMin=honMinJUS,effMax=honMaxJUS;if(honMaxJUS<legalMin){warn='todo';effMin=legalMin;effMax=legalMin;}else if(honMinJUS<legalMin){warn='piso';effMin=legalMin;}calcSt.last={base,baseJUS,t,honMinJUS,honMaxJUS,legalMin,effMin,effMax,warn};calcSt.applied=null;renderCalc();}
function calcUsar(){const sel=document.getElementById('calc_use_causa');const id=(sel&&sel.value)?sel.value:((st.vista==='ficha'&&st.actual&&!st.cliente)?st.actual:null);if(!id){alert('Elegí la causa a la que querés volcar el valor.');return;}const c=get(id);if(!c)return;const inp=document.getElementById('calc_use');let v=inp?+inp.value:0;if(!(v>=0))v=0;if(!c.honorarios)c.honorarios={ius:0,gastos:[],pagos:[]};c.honorarios.ius=v;persist();calcSt.applied={car:c.caratula,v};if(st.vista==='ficha'&&st.actual===id)renderFicha();renderSection();}
function cShort(s){s=String(s||'');return s.length>44?s.slice(0,42)+'…':s;}
function useBlock(enFicha,c,val){
  const opts=causas.map(x=>`<option value="${x.id}" ${(enFicha&&c&&c.id===x.id)?'selected':''}>${esc(cShort(x.caratula))}</option>`).join('');
  let msg='';
  if(calcSt.applied)msg='<div class="cu-ok">✓ Cargado '+fjus(calcSt.applied.v)+' IUS en '+esc(cShort(calcSt.applied.car))+'.</div>';
  return '<div class="calc-use"><div class="cu-lbl">Volcar a una causa</div>'
    +'<select id="calc_use_causa" class="cu-sel"><option value="">— Elegí la causa —</option>'+opts+'</select>'
    +'<div class="calc-use-row"><input type="number" id="calc_use" min="0" step="0.5" value="'+attr(val)+'"><button onclick="calcUsar()">Usar en esta causa</button></div>'+msg+'</div>';
}
function renderCalc(){
  const body=document.getElementById('sideContent');if(!body)return;
  const vIus=+config.valorIUS||0;
  const enFicha=(st.vista==='ficha'&&st.actual&&!st.cliente);
  const cActual=enFicha?get(st.actual):null;
  let h='<div class="calc-modes">'
    +'<button class="calc-mode '+(calcSt.mode==='fija'?'on':'')+'" onclick="setCalcMode(\'fija\')">Materia (monto fijo)</button>'
    +'<button class="calc-mode '+(calcSt.mode==='economica'?'on':'')+'" onclick="setCalcMode(\'economica\')">Cálculo económico</button></div>'
    +'<div class="calc-ius"><span>Valor del IUS: <b>'+(vIus?fmtPesos(vIus):'sin cargar')+'</b></span><button class="lk" onclick="openModal({tipo:\'configius\'})">Cambiar</button></div>';
  if(calcSt.mode==='fija'){
    h+='<div class="calc-search"><input type="text" id="calcQ" placeholder="Buscar materia (divorcio, alimentos…)" value="'+attr(calcSt.q)+'" oninput="calcQinput(this.value)"></div>'
      +'<div id="calcList" style="margin-top:12px">'+calcListHtml()+'</div>';
    if(calcSt.sel!=null&&ARANCEL_FIJOS[calcSt.sel]){
      const it=ARANCEL_FIJOS[calcSt.sel];
      h+='<div class="calc-res">'
        +'<div class="rrow"><span class="rk">Materia</span><span class="rv">'+esc(it.l)+'</span></div>'
        +'<div class="rrow"><span class="rk">Honorario (mínimo legal)</span><span class="rv big">'+fjus(it.jus)+' JUS</span></div>'
        +'<div class="rrow"><span class="rk">Equivalente en pesos</span><span class="rv">'+(vIus?fmtPesos(it.jus*vIus):'—')+'</span></div>'
        +(it.nota?'<div class="calc-fund">▸ '+esc(it.nota)+'</div>':'')
        +'<div class="calc-fund">Fundamento: Ley 5724, '+esc(it.art)+'. Es el <b>mínimo</b>; el/la juez/a no puede regular por debajo (art. 17 in fine).</div>'
        +useBlock(enFicha,cActual,it.jus)+'</div>';
    }
  } else {
    const showOtro=calcSt.tipo==='otro';
    h+='<div class="calc-field"><label>Monto base del asunto (en pesos)</label><input type="text" id="calc_base" inputmode="decimal" placeholder="Ej. 18.000.000" value="'+attr(calcSt.base?fmtMiles(parseMiles(calcSt.base)):'')+'" oninput="numInput(this);calcSt.base=this.value" onblur="numBlur(this);calcSt.base=this.value"></div>'
      +'<div class="calc-field"><label>Tipo de proceso (define el mínimo del art. 23)</label>'
      +'<select id="calc_tipo" onchange="calcSt.tipo=this.value;renderCalc()">'
      +'<option value="conocimiento" '+(calcSt.tipo==='conocimiento'?'selected':'')+'>Conocimiento — mín. 20 JUS</option>'
      +'<option value="ejecucion" '+(calcSt.tipo==='ejecucion'?'selected':'')+'>Ejecución o voluntario — mín. 10 JUS</option>'
      +'<option value="otro" '+(calcSt.tipo==='otro'?'selected':'')+'>Otro — definir mínimo</option>'
      +'</select></div>'
      +(showOtro?'<div class="calc-field"><label>Mínimo aplicable (en JUS)</label><input type="number" id="calc_otromin" min="0" step="1" value="'+attr(calcSt.otroMin)+'" oninput="calcSt.otroMin=this.value"></div>':'')
      +'<button class="calc-btn" onclick="calcEco()">Calcular</button>';
    const r=calcSt.last;
    if(r){
      if(r.err==='sinius')h+='<div class="calc-warn">Cargá primero el valor del IUS (botón “Cambiar”, arriba) para convertir el monto a JUS.</div>';
      else if(r.err==='sinbase')h+='<div class="calc-warn">Ingresá un monto base mayor a cero.</div>';
      else{
        const dist=fjus(r.effMax)!==fjus(r.effMin);
        h+='<div class="calc-res">'
          +'<div class="rrow"><span class="rk">Base</span><span class="rv">'+fmtPesos(r.base)+' · '+fjus(r.baseJUS)+' JUS</span></div>'
          +'<div class="rrow"><span class="rk">Tramo (art. 25)</span><span class="rv">'+esc(r.t.r)+' · '+r.t.min+'%–'+r.t.max+'%</span></div>'
          +'<div class="rrow"><span class="rk">Honorario</span><span class="rv big">'+fjus(r.effMin)+(dist?' – '+fjus(r.effMax):'')+' JUS</span></div>'
          +'<div class="rrow"><span class="rk">En pesos</span><span class="rv">'+fmtPesos(r.effMin*vIus)+(dist?' – '+fmtPesos(r.effMax*vIus):'')+'</span></div>';
        if(r.warn==='todo')h+='<div class="calc-warn"><b>Aplica el mínimo legal.</b> El cálculo daba '+fjus(r.honMinJUS)+'–'+fjus(r.honMaxJUS)+' JUS, por debajo del mínimo de '+fjus(r.legalMin)+' JUS (art. 23). El art. 25 (in fine) impide regular por debajo, así que corresponde <b>'+fjus(r.legalMin)+' JUS</b>.</div>';
        else if(r.warn==='piso')h+='<div class="calc-warn"><b>Piso elevado al mínimo legal.</b> El piso del cálculo ('+fjus(r.honMinJUS)+' JUS) quedaba por debajo del mínimo de '+fjus(r.legalMin)+' JUS (art. 23). El rango aplicable arranca en <b>'+fjus(r.legalMin)+' JUS</b> (art. 25 in fine).</div>';
        h+='<div class="calc-fund">Fundamento: Ley 5724, art. 25 (escala) y art. 23 (mínimos). Resultado orientativo; la regulación final la hace el/la juez/a (art. 17).</div>'
          +useBlock(enFicha,cActual,Math.round(r.effMin*100)/100)+'</div>';
      }
    }
  }
  h+='<div class="calc-note">Herramienta orientativa según la Ley N° 5724 de Catamarca. No reemplaza la regulación judicial.</div>';
  body.innerHTML=h;
}
function calcInit(){calcSt.open=window.innerWidth>=1200;document.body.classList.toggle('calc-open',calcSt.open);renderSide();}
function syncUltimo(c){if(c.bitacora.length){const b=c.bitacora[0];c.ultimoMov={fecha:b.fecha,texto:b.texto,nuevo:b.nuevo};}}
function addMov(id){const c=get(id);const fEl=document.getElementById('nm_fecha');const tEl=document.getElementById('nm_texto');const t=(tEl.value||'').trim();if(!t){tEl.focus();return;}const fecha=isoToDMY(fEl.value);c.bitacora.unshift({fecha,texto:t,nuevo:true});syncUltimo(c);persist();renderFicha();}
function editMov(id,i){st.editMov={id,i};renderFicha();setTimeout(()=>{const e=document.getElementById('me_texto');if(e){e.focus();e.setSelectionRange(e.value.length,e.value.length);}},20);}
function cancelMov(){st.editMov=null;renderFicha();}
function saveMov(id,i){const c=get(id);const fEl=document.getElementById('me_fecha');const tEl=document.getElementById('me_texto');const f=(fEl.value||'').trim();const t=(tEl.value||'').trim();if(f)c.bitacora[i].fecha=f;if(t)c.bitacora[i].texto=t;st.editMov=null;syncUltimo(c);persist();renderFicha();}
function delMov(id,i){const c=get(id);if(c.bitacora.length<=1){alert('La causa debe conservar al menos un movimiento.');return;}if(!confirm('¿Eliminar este movimiento?'))return;c.bitacora.splice(i,1);st.editMov=null;syncUltimo(c);persist();renderFicha();}
function toggleVis(id,i){const c=get(id);c.documentos[i].v=c.documentos[i].v==="cli"?"int":"cli";persist();renderFicha();}
function openModal(m){st.modal=m;render();if(['pedirExp','agregar','editar'].includes(m.tipo))setTimeout(()=>{const f=document.querySelector('.modal input,.modal textarea');if(f)f.focus();},30);}
function closeModal(){st.modal=null;render();}
function elegirEstado(id,e){const c=get(id);if(e==="tramite"&&!c.expediente){c.estado="tramite";persist();openModal({tipo:'pedirExp',id});return;}c.estado=e;persist();closeModal();if(st.vista==="ficha")renderFicha();}
function guardarExp(id){const c=get(id);const v=document.getElementById("expinput").value.trim();if(v)c.expediente=v;c.estado="tramite";persist();closeModal();if(st.vista==="ficha")renderFicha();}
function guardarEdit(id){const c=get(id);const g=i=>document.getElementById(i).value;
  c.caratula=g('e_car').trim()||c.caratula;c.estado=g('e_est');
  c.materia=g('e_mat').split(',').map(s=>s.trim()).filter(Boolean);if(!c.materia.length)c.materia=['Sucesión'];
  c.expediente=g('e_exp').trim()||null;c.cuij=g('e_cuij').trim()||null;c.objeto=g('e_obj').trim();
  c.fuero=g('e_fuero').trim();c.juzgado=g('e_juz').trim();c.juez=g('e_juez').trim();c.secretaria=g('e_sec').trim();
  c.actor=g('e_act').trim();c.actorPat=g('e_actpat').trim();c.demandado=g('e_dem').trim();c.demandadoPat=g('e_dempat').trim();c.cliente=g('e_cli').trim();c.clienteCalidad=g('e_ccal').trim();
  c.dirJuzId=(document.getElementById('e_dirjuz')||{}).value||null;
  persist();closeModal();if(st.vista==="ficha")renderFicha();}
function irACausa(id,tab){st.modal=null;st.actual=id;st.vista="ficha";st.tab=tab;st.cliente=false;st.editPend=null;window.scrollTo(0,0);render();}
function resolver(id,idx,opcion){const c=get(id);const a=c.alertas[idx];if(!a)return;
  if(a.t==='eleccion'&&a.campo&&opcion)c[a.campo]=opcion;
  c.alertas.splice(idx,1);persist();
  if(st.modal&&st.modal.tipo==='resolver')st.modal={tipo:'verificar'};
  render();if(st.vista==="ficha"&&!st.modal)renderFicha();}
function postergar(id,idx){const c=get(id);const a=c.alertas[idx];if(a)a.postergada=true;persist();
  if(st.modal&&st.modal.tipo==='resolver')st.modal={tipo:'verificar'};
  render();if(st.vista==="ficha"&&!st.modal)renderFicha();}
function guardarNueva(){const g=id=>{const el=document.getElementById(id);return el?el.value.trim():'';};const car=g("n_car");if(!car){alert("La carátula es obligatoria.");return;}
  const est=((document.getElementById("n_est")||{}).value==='tramite')?'tramite':'preparacion';
  const exp=g("n_exp")||null;
  /* Cliente: existente (del selector) o nuevo (texto) */
  const sel=(document.getElementById("n_cli_sel")||{}).value||'';
  const cliName=(sel&&sel!=='__nuevo__')?sel:g("n_cli_nuevo");
  /* #5 — aviso de causa duplicada por N° de expediente (un mismo cliente puede tener
     varias causas, pero no dos con el mismo expediente) */
  if(exp){const norm=s=>String(s||'').replace(/\s/g,'').toLowerCase();
    const dup=causas.find(c=>c.expediente&&norm(c.expediente)===norm(exp));
    if(dup){if(!confirm('Ya existe una causa con el expediente '+exp+':\n"'+dup.caratula+'".\n\n¿Crear otra causa igual de todos modos?'))return;}}
  const enTr=est==='tramite';
  const txtUlt=enTr?'Causa en trámite (alta manual). Verificá el último movimiento en el expediente.':'Causa creada como borrador en preparación.';
  const txtAlta=enTr?'Alta de la causa en trámite (carga manual).':'Alta de la causa en preparación (carga manual).';
  const pend=enTr
    ?[{t:"Verificar el último movimiento en el expediente (IURIX).",done:false},{t:"Completar datos y documentación.",done:false}]
    :[{t:"Completar datos y documentación.",done:false},{t:"Preparar escrito de inicio.",done:false}];
  causas.unshift({id:"nueva-"+Date.now(),estado:est,procesal:null,materia:[g("n_mat")||"Sucesión"],
    caratula:car,cliente:cliName||"A completar",expediente:exp,cuij:null,objeto:g("n_obj")||"A completar.",
    fuero:g("n_fuero")||"A definir",juzgado:g("n_juz")||"A definir al presentar",juez:g("n_juez")||"—",secretaria:g("n_sec")||"—",dirJuzId:(document.getElementById("n_dirjuz")||{}).value||null,
    letrada:g("n_let")||"Dra. Rocío Cristal Luján",clienteEs:"activa",actorRol:"Actora",actor:g("n_par")||"A completar",actorPat:g("n_let")||"Dra. Rocío Cristal Luján",demandadoRol:"Demandado",demandado:"A completar",demandadoPat:"",clienteCalidad:"por derecho propio",posicion:"—",
    ultimoMov:{fecha:hoy(),texto:txtUlt},
    bitacora:[{fecha:hoy(),texto:txtAlta,inicio:true}],
    documentos:[],pendientes:pend,
    alertas:[],ficha:"",folder:""});
  persist();closeModal();
  if(cliName&&cliName!=='A completar'&&!clientes[cliName]){st.cliForm={nombre:cliName,tipo:'fisica'};openModal({tipo:'clidatos'});}}
function hoy(){const d=new Date();return String(d.getDate()).padStart(2,'0')+"/"+String(d.getMonth()+1).padStart(2,'0')+"/"+d.getFullYear();}
/* #2 — Eliminar una causa completa (con doble confirmación, por seguridad) */
function delCausa(id){const c=get(id);if(!c)return;
  if(!confirm('¿Eliminar la causa "'+c.caratula+'"?\n\nSe borra TODO lo de esta causa: bitácora, documentos, pendientes y honorarios. Esta acción NO se puede deshacer.'))return;
  if(!confirm('Última confirmación: esta eliminación es DEFINITIVA.\n\n¿Eliminar la causa?'))return;
  causas=causas.filter(x=>x.id!==id);persist();
  st.actual=null;st.vista='tablero';st.tab='datos';st.editPend=null;
  if(typeof closeModal==='function')closeModal();
  navTo('causas');}
/* ===== CADUCIDAD DE INSTANCIA (CPCyC Catamarca, Ley 2339, arts. 310-318) ===== */
const CAD_TIPOS={
 ordinario:{l:"Ordinario / conocimiento (1ª inst.) — 6 meses",meses:6},
 sumarisimo:{l:"Sumarísimo — 3 meses",meses:3},
 ejecutivo:{l:"Ejecutivo / ejecución especial — 3 meses",meses:3},
 incidente:{l:"Incidente — 3 meses",meses:3},
 segunda:{l:"Segunda instancia (apelación) — 3 meses",meses:3},
 nocaduca:{l:"No caduca (sucesorio · voluntario · ejecución de sentencia · alimentos/familia)",meses:0}
};
function inferCad(c){
  const m=c.materia||[];const has=x=>m.includes(x);
  if(has("Sucesión"))return "nocaduca";
  if(has("Alimentos")||has("Régimen de comunicación")||has("Homologación")||has("Divorcio")||has("Filiación"))return "nocaduca";
  if(has("Ejecución"))return "ejecutivo";
  return "ordinario";
}
function parseFechaCad(s){
  if(!s)return null;s=String(s).replace(/[–—]/g,'-');
  let m=s.match(/(\d{1,2})\/(\d{1,2})\/(\d{4})/g);
  if(m){const p=m[m.length-1].split('/');return new Date(+p[2],(+p[1])-1,+p[0]);}
  m=s.match(/(\d{1,2})\/(\d{4})/g);
  if(m){const p=m[m.length-1].split('/');return new Date(+p[1],(+p[0])-1,1);}
  m=s.match(/(19|20)\d{2}/g);
  if(m){return new Date(+m[m.length-1],0,1);}
  return null;
}
function calcCaducidad(c){
  const tipo=c.cadTipo||'ordinario';
  const meses=(CAD_TIPOS[tipo]||{}).meses||0;
  if(tipo==='nocaduca'||!meses)return {tipo,nocaduca:true};
  let lastImp=null,lastImpDate=null;
  (c.bitacora||[]).forEach(b=>{if(b.imp){const d=parseFechaCad(b.fecha);if(d&&(!lastImpDate||d>lastImpDate)){lastImpDate=d;lastImp=b;}}});
  const pausa=(c.procesal==='A DESPACHO');
  if(!lastImpDate)return {tipo,meses,sinImpulso:true,pausa};
  const venc=new Date(lastImpDate);venc.setMonth(venc.getMonth()+meses);
  const hoy=new Date();hoy.setHours(0,0,0,0);
  const diasRest=Math.round((venc-hoy)/86400000);
  const nivel=diasRest<0?'venc':(diasRest<=15?'rojo':(diasRest<=45?'amar':'verde'));
  return {tipo,meses,lastImp,lastImpDate,venc,diasRest,nivel,pausa};
}
function dmyCad(d){if(!d)return '—';return String(d.getDate()).padStart(2,'0')+'/'+String(d.getMonth()+1).padStart(2,'0')+'/'+d.getFullYear();}
function cadFundNo(c){
  const m=c.materia||[];
  if(m.includes("Sucesión"))return "Los procesos sucesorios y voluntarios no caducan (art. 313 inc. 2 CPCyC).";
  if(m.includes("Alimentos")||m.includes("Régimen de comunicación")||m.includes("Homologación")||m.includes("Divorcio")||m.includes("Filiación"))return "Alimentos y familia con menores: sin alerta (criterio adoptado; la caducidad en alimentos es discutida).";
  return "Configurada como no caducable.";
}
function cadDetalle(r,pausa){
  const dr=r.diasRest;const cls=pausa?'pausa':r.nivel;
  const txt=dr<0?('Plazo vencido hace '+Math.abs(dr)+' días'):('Faltan '+dr+' días');
  return `<div class="cad-detalle">
    <div class="cad-row"><span>Último acto de impulso</span><b>${esc(r.lastImp.fecha)}</b></div>
    <div class="cad-row"><span>Plazo legal</span><b>${r.meses} meses</b></div>
    <div class="cad-row"><span>Vence (estimado)</span><b>${dmyCad(r.venc)}</b></div>
    <div class="cad-semaforo ${cls}">${pausa?'En pausa (a despacho)':txt}</div></div>`;
}
function cadLeyenda(c){
  if(c.clienteEs==='pasiva')return `<div class="cad-ley demandado">Representás al <b>demandado</b>: si el plazo vence, podés <b>acusar la caducidad</b> de instancia (art. 315). Es una oportunidad procesal.</div>`;
  return `<div class="cad-ley actor">Representás al <b>actor</b>: la carga de impulsar es tuya. Si el plazo vence sin impulso, el demandado puede acusar la caducidad (art. 315).</div>`;
}
function caducidadCard(c){
  const r=calcCaducidad(c);
  const cur=c.cadTipo||'ordinario';
  const tipoSel=`<select id="cad_tipo" onchange="setCadTipo('${c.id}')">`+Object.keys(CAD_TIPOS).map(k=>`<option value="${k}" ${cur===k?'selected':''}>${esc(CAD_TIPOS[k].l)}</option>`).join('')+`</select>`;
  let body='';
  if(r.nocaduca){
    body=`<div class="cad-status nocad"><b>No caduca.</b> ${cadFundNo(c)}</div>`;
  } else if(r.pausa){
    body=`<div class="cad-status pausa">⏸ <b>En pausa</b> — la causa está <b>a despacho</b>. Mientras dependa de una resolución del juzgado, la caducidad no corre (art. 313 inc. 3).</div>`+(r.lastImpDate?cadDetalle(r,true):'')+cadLeyenda(c);
  } else if(r.sinImpulso){
    body=`<div class="cad-status sininfo">Marcá en la línea de tiempo (de abajo) el <b>último acto de impulso</b> con el botón ⚖ para activar el conteo.</div>`+cadLeyenda(c);
  } else {
    body=cadDetalle(r,false)+cadLeyenda(c);
  }
  return `<div class="cad-card">
    <div class="cad-head"><span class="cad-ic">⚖</span><span>Caducidad de instancia</span></div>
    <div class="cad-tipo"><label>Tipo de proceso (define el plazo)</label>${tipoSel}</div>
    ${body}
    <div class="cad-warn">⚠ Cálculo orientativo. Verificá siempre el plazo en el expediente y en la norma aplicable antes de actuar.</div>
    <div class="cad-foot">CPCyC de Catamarca (Ley 2339, arts. 310-318). No descuenta ferias (enero/julio), por eso avisa con margen.</div></div>`;
}
function setCadTipo(id){const c=get(id);const v=document.getElementById('cad_tipo').value;if(v)c.cadTipo=v;persist();renderFicha();}
function toggleImp(id,i){const c=get(id);c.bitacora[i].imp=!c.bitacora[i].imp;persist();renderFicha();}
/* ===== BARRA LATERAL: nav + secciones (Calendario / Audiencias / Honorarios / Tareas) ===== */
const MESES=["enero","febrero","marzo","abril","mayo","junio","julio","agosto","septiembre","octubre","noviembre","diciembre"];
const DOW=["Lun","Mar","Mié","Jue","Vie","Sáb","Dom"];
const AUD='gestor_aud_v1';
let audiencias=[];
let sideSt={sec:'calendario',calY:null,calM:null,calSel:'',af:null};
async function loadAud(){try{if(window.storage){const r=await window.storage.get(AUD);if(r&&r.value)return JSON.parse(r.value);}}catch(e){}try{if(typeof localStorage!=='undefined'){const v=localStorage.getItem(AUD);if(v)return JSON.parse(v);}}catch(e){}return null;}
async function saveAud(){const d=JSON.stringify(audiencias);try{if(window.storage){await window.storage.set(AUD,d);return;}}catch(e){}try{if(typeof localStorage!=='undefined')localStorage.setItem(AUD,d);}catch(e){}}
function persistAud(){saveAud();}

function navHTML(){const s=sideSt.sec;const b=(id,ic,l)=>`<button class="side-tab ${s===id?'on':''}" onclick="setSide('${id}')">${ic} ${l}</button>`;
  return `<div class="side-nav">${b('calendario','📅','Calendario')}${b('audiencias','⚖','Audiencias')}${b('honorarios','$','Honorarios')}${b('tareas','✓','Tareas')}</div>`;}
function setSide(sec){sideSt.sec=sec;renderSide();}
function renderSection(){const s=sideSt.sec;if(s==='honorarios')renderCalc();else if(s==='audiencias')renderAudiencias();else if(s==='tareas')renderTareas();else renderCalendario();}
function renderSide(){const body=document.getElementById('calcBody');if(!body)return;body.innerHTML=navHTML()+'<div class="side-content" id="sideContent"></div>';renderSection();}

/* ----- Calendario ----- */
function audFechaDMY(s){if(!s)return '';const p=String(s).split('-');return p.length===3?(p[2]+'/'+p[1]+'/'+p[0]):s;}
function audItem(a){
  if(a.tipo==='cita'){
    const virt=a.modalidad==='virtual';
    const mod=`<span class="aud-badge cita">${virt?'Cita virtual':'Cita presencial'}</span>`;
    const place=virt
      ? (a.link?`<a class="aud-link" href="${attr(a.link)}" target="_blank" rel="noopener">🔗 Unirse a la videollamada</a>`:'<span class="aud-place pend">Sin enlace cargado</span>')
      : (a.lugar?`<span class="aud-place">📍 ${esc(a.lugar)}</span>`:'');
    const info=esc(a.cliente||'(sin cliente)')+(a.detalle?(' — '+esc(a.detalle)):'');
    return `<div class="aud-it"><span class="aud-del" onclick="delAudiencia('${a.id}')" title="Eliminar">×</span><span class="aud-d">${audFechaDMY(a.fecha)}${a.hora?(' · '+esc(a.hora)+' hs'):''}</span>${mod}<div class="aud-info">${info}</div><div class="aud-asiste cita">👤 Cita con ${esc(a.cliente||'el cliente')} · aparece en su portal</div>${place?('<div class="aud-place-wrap">'+place+'</div>'):''}</div>`;
  }
  const badge=a.tipo==='juzgado'?'<span class="aud-badge juz">Juzgado</span>':'<span class="aud-badge med">Mediación</span>';
  let info='';
  if(a.tipo==='juzgado'){const c=get(a.causaId);info=(c?esc(cShort(c.caratula)):'(causa eliminada)')+(a.detalle?(' — '+esc(a.detalle)):'');}
  else{info=esc(a.cliente||'(sin cliente)')+(a.materia?(' · '+esc(a.materia)):'');}
  const asiste=a.cliAsiste?`<div class="aud-asiste">👤 El cliente debe asistir${a.cliente?(' — '+esc(a.cliente)):''}</div>`:'';
  return `<div class="aud-it"><span class="aud-del" onclick="delAudiencia('${a.id}')" title="Eliminar">×</span><span class="aud-d">${audFechaDMY(a.fecha)}${a.hora?(' · '+esc(a.hora)+' hs'):''}</span>${badge}<div class="aud-info">${info}</div>${asiste}</div>`;
}
function renderCalendario(){
  const cont=document.getElementById('sideContent');if(!cont)return;
  if(sideSt.calY==null){const n=new Date();sideSt.calY=n.getFullYear();sideSt.calM=n.getMonth();}
  const y=sideSt.calY,m=sideSt.calM;
  const off=(new Date(y,m,1).getDay()+6)%7;const dim=new Date(y,m+1,0).getDate();
  const today=new Date();
  const byDay={};audiencias.forEach(a=>{(byDay[a.fecha]=byDay[a.fecha]||[]).push(a);});
  let cells='';let monthFers=[];let hasFeria=false;
  for(let i=0;i<off;i++)cells+='<div class="cal-cell"></div>';
  for(let d=1;d<=dim;d++){
    const key=y+'-'+String(m+1).padStart(2,'0')+'-'+String(d).padStart(2,'0');
    const list=byDay[key]||[];
    const isToday=(y===today.getFullYear()&&m===today.getMonth()&&d===today.getDate());
    const sel=sideSt.calSel===key;
    let dots='';if(list.length){const hasJ=list.some(a=>a.tipo==='juzgado'),hasM=list.some(a=>a.tipo==='mediacion'),hasCi=list.some(a=>a.tipo==='cita'),hasC=list.some(a=>a.cliAsiste);dots='<div class="cal-dots">'+(hasJ?'<span class="cal-dot juz"></span>':'')+(hasM?'<span class="cal-dot med"></span>':'')+(hasCi?'<span class="cal-dot cita"></span>':'')+(hasC?'<span class="cal-dot cli"></span>':'')+'</div>';}
    const dt_=new Date(y,m,d);const fer_=ferMatch(dt_);const feria_=cpInFeria(dt_,true);
    let ferCls_='';
    if(fer_){ferCls_=(fer_.tipo==='provincial'?'fer-prov':'fer-nac');monthFers.push({d:d,nombre:fer_.nombre||'Feriado',tipo:fer_.tipo});}
    else if(feria_){ferCls_='fer-feria';hasFeria=true;}
    cells+=`<div class="cal-cell clk ${list.length?'has':''} ${isToday?'today':''} ${sel?'sel':''} ${ferCls_}" onclick="calSel('${key}')" title="${fer_?attr(fer_.nombre||'Feriado'):(feria_?'Feria judicial':'')}"><span>${d}</span>${dots}</div>`;
  }
  const dows=DOW.map(d=>`<div class="cal-dow">${d}</div>`).join('');
  let keys=Object.keys(byDay).filter(k=>{const dt=new Date(k+'T00:00:00');return dt.getFullYear()===y&&dt.getMonth()===m;});
  if(sideSt.calSel)keys=keys.filter(k=>k===sideSt.calSel);
  keys.sort();
  const listHtml=keys.length?keys.map(k=>byDay[k].slice().sort((a,b)=>(a.hora||'').localeCompare(b.hora||'')).map(audItem).join('')).join(''):`<div class="vacio" style="padding:12px 2px">${sideSt.calSel?'Sin audiencias ese día.':'Sin audiencias este mes.'}</div>`;
  cont.classList.add('wide');
  cont.innerHTML=`<div class="side-sectit">Calendario</div>
    <div class="cal-2col">
      <div class="cal-left">
        <div class="cal-head"><button class="cal-nav" onclick="calMove(-1)">‹</button><div class="cal-title">${MESES[m]} ${y}</div><button class="cal-nav" onclick="calMove(1)">›</button></div>
        <div class="cal-grid">${dows}${cells}</div>
        ${sideSt.calSel?`<div class="cal-selbar"><button class="cal-add" onclick="agendarEnDia('${sideSt.calSel}')">+ Agendar el ${audFechaDMY(sideSt.calSel)}</button><button class="cal-verall" onclick="calSel('')">‹ Ver todo el mes</button></div>`:`<div class="cal-hint">Tocá un día para verlo o agendar una audiencia.</div>`}
        <div class="cal-leyenda"><span><i class="cal-dot juz"></i>Juzgado</span><span><i class="cal-dot med"></i>Mediación</span><span><i class="cal-dot cita"></i>Cita con cliente</span><span><i class="cal-dot cli"></i>Asiste el cliente</span><span><i class="cal-sw nac"></i>Feriado nacional</span><span><i class="cal-sw prov"></i>Feriado provincial</span><span><i class="cal-sw feria"></i>Feria judicial</span></div>
        ${(monthFers.length||hasFeria)?`<div class="cal-fers"><div class="cal-fers-h">Feriados de ${MESES[m]}</div>${monthFers.map(f=>`<div class="cal-fer-item"><i class="cal-sw ${f.tipo==='provincial'?'prov':'nac'}"></i><b>${String(f.d).padStart(2,'0')}/${String(m+1).padStart(2,'0')}</b> ${esc(f.nombre)}</div>`).join('')}${hasFeria?`<div class="cal-fer-item"><i class="cal-sw feria"></i><b>Feria</b> Receso judicial</div>`:''}</div>`:''}
      </div>
      <div class="cal-right">
        <div class="cal-right-h">${sideSt.calSel?('Audiencias del '+audFechaDMY(sideSt.calSel)):('Audiencias de '+MESES[m]+' '+y)}</div>
        <div class="aud-list">${listHtml}</div>
        <div class="calc-note" style="margin-top:16px">Calendario interno de la app. Las citas con clientes se ven en el portal del cliente. La sincronización con el calendario propio del cliente (su Google Calendar) y los avisos llegan con la versión conectada.</div>
      </div>
    </div>`;
}
function calMove(d){sideSt.calM+=d;if(sideSt.calM<0){sideSt.calM=11;sideSt.calY--;}else if(sideSt.calM>11){sideSt.calM=0;sideSt.calY++;}sideSt.calSel='';renderSection();}
function calSel(k){sideSt.calSel=k||'';renderSection();}
function agendarEnDia(key){if(!sideSt.af)sideSt.af={tipo:'juzgado',fecha:'',hora:'',causa:'',detalle:'',cli:'',mat:'Derecho de familia',cliAsiste:false,modal:'presencial',lugar:'',link:'',lugarManual:false};sideSt.af.fecha=key;sideSt.sec='audiencias';st.nav='audiencias';window.scrollTo(0,0);render();}
function hoyKey(){const d=new Date();return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0');}
function notifs(){const hk=hoyKey();return audiencias.filter(a=>a.cliAsiste&&a.fecha&&a.fecha>=hk).sort((a,b)=>((a.fecha||'')+(a.hora||'')).localeCompare((b.fecha||'')+(b.hora||'')));}
function citasProx(){const hk=hoyKey();return audiencias.filter(a=>a.tipo==='cita'&&a.fecha&&a.fecha>=hk).sort((a,b)=>((a.fecha||'')+(a.hora||'')).localeCompare((b.fecha||'')+(b.hora||'')));}
function pagosInformados(){const out=[];causas.forEach(c=>{((c.honorarios&&c.honorarios.pagos)||[]).forEach((p,i)=>{if(p.confirmado===false)out.push({cid:c.id,cliente:c.cliente,caratula:cShort(c.caratula),ius:+p.ius||0,fecha:p.fecha,i:i,compArch:p.compArch});});});return out;}
function irAHonorarios(cid){st.actual=cid;st.vista='ficha';st.tab='honorarios';st.cliente=false;window.scrollTo(0,0);render();}
function irACausa(cid){st.actual=cid;st.vista='ficha';st.tab='datos';st.cliente=false;window.scrollTo(0,0);render();}
/* Causas con caducidad de instancia próxima o vencida. */
function caducidadesProximas(){const out=[];causas.forEach(c=>{if(c.estado==='finalizada'||c.estado==='suspenso')return;const r=calcCaducidad(c);if(r&&r.venc&&!r.nocaduca&&!r.sinImpulso&&!r.pausa&&['venc','rojo','amar'].indexOf(r.nivel)>=0){out.push({cid:c.id,caratula:cShort(c.caratula),cliente:c.cliente,venc:r.venc,dias:r.diasRest,nivel:r.nivel});}});out.sort((a,b)=>a.dias-b.dias);return out;}
/* Clientes/causas con saldo impago hace más de 30 días. */
function morosos(){const v=+config.valorIUS||0;const out=[];causas.forEach(c=>{if(c.estado==='finalizada')return;const h=c.honorarios||{};const tot=+h.ius||0;if(tot<=0)return;const pag=(h.pagos||[]).filter(p=>p.confirmado!==false).reduce((a,p)=>a+(+p.ius||0),0);const sal=tot-pag;if(sal<=0)return;const fechas=(h.pagos||[]).filter(p=>p.confirmado!==false).map(p=>parseDMY(p.fecha)).filter(Boolean).sort((a,b)=>b-a);const ult=fechas[0]||parseDMY(((c.bitacora||[]).slice(-1)[0]||{}).fecha);const ds=diasDesde(ult);if(ds!=null&&ds>30)out.push({cid:c.id,caratula:cShort(c.caratula),cliente:c.cliente,sal:sal*v,ult:ult,ds:ds});});out.sort((a,b)=>b.ds-a.ds);return out;}
function urgentesHoyManana(){const hk=hoyKey();const d=new Date();d.setDate(d.getDate()+1);const mk=d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0');return audiencias.filter(a=>a.fecha===hk||a.fecha===mk).sort((a,b)=>((a.fecha||'')+(a.hora||'')).localeCompare((b.fecha||'')+(b.hora||'')));}
function compartidasConmigo(){return causas.filter(c=>c._compartida);}
function iusDesactualizado(){if(!config.iusFecha)return true;const d=parseDMY(config.iusFecha);if(!d)return false;const n=new Date();return d.getFullYear()!==n.getFullYear()||d.getMonth()!==n.getMonth();}
let __avAuto={docs:0,clis:0};
async function cargarAvisosAuto(){
  try{
    const r=await fetch('/api/avisos',{credentials:'same-origin'});const j=await r.json();
    if(!j||j.ok===false)return;
    const docs=(j.data&&j.data.documentos)||[];const clis=(j.data&&j.data.clientes)||[];
    __avAuto={docs:docs.length,clis:clis.length};
    const dc=document.getElementById('avAutoDocs');
    if(dc)dc.innerHTML=docs.length?('<div class="avi-sec"><div class="avi-sec-h">Documentos nuevos <span class="avi-n">'+docs.length+'</span></div><div class="avi-list">'+docs.map(d=>'<div class="avi-card"><div class="avi-ic">📄</div><div class="avi-body"><div class="avi-top"><b>'+esc(d.quien||(d.rol==='cliente'?'Un cliente':'Un colega'))+'</b> subió un documento.<span class="avi-tag man">NUEVO</span></div><div class="avi-meta">'+esc(d.nombre||'Documento')+'</div><div class="avi-when">📅 '+esc(String(d.creado_en||'').slice(0,10))+'</div></div></div>').join('')+'</div></div>'):'';
    const cc=document.getElementById('avAutoClis');
    if(cc)cc.innerHTML=clis.length?('<div class="avi-sec"><div class="avi-sec-h">Clientes que ingresaron <span class="avi-n">'+clis.length+'</span></div><div class="avi-list">'+clis.map(c=>'<div class="avi-card"><div class="avi-ic">👤</div><div class="avi-body"><div class="avi-top"><b>'+esc(c.nombre||c.email)+'</b> ingresó por primera vez a su portal.<span class="avi-tag man">NUEVO</span></div><div class="avi-meta">'+esc(c.email||'')+'</div><div class="avi-when">📅 '+esc(String(c.primer_acceso||'').slice(0,10))+'</div></div></div>').join('')+'</div></div>'):'';
    updateNotifBell();
  }catch(e){}
}
function urlB64ToUint8(base64){const pad='='.repeat((4-base64.length%4)%4);const b64=(base64+pad).replace(/-/g,'+').replace(/_/g,'/');const raw=atob(b64);const arr=new Uint8Array(raw.length);for(let i=0;i<raw.length;i++)arr[i]=raw.charCodeAt(i);return arr;}
async function suscribirPush(){
  try{
    if(!('serviceWorker' in navigator)||!('PushManager' in window))return false;
    const reg=await navigator.serviceWorker.ready;
    let sub=await reg.pushManager.getSubscription();
    if(!sub){
      const r=await fetch('/api/push/clave',{credentials:'same-origin'});const j=await r.json();
      const clave=j&&j.data&&j.data.clave;if(!clave)return false;
      sub=await reg.pushManager.subscribe({userVisibleOnly:true,applicationServerKey:urlB64ToUint8(clave)});
    }
    const r2=await fetch('/api/push/subscribe',{method:'POST',credentials:'same-origin',headers:{'Content-Type':'application/json'},body:JSON.stringify({endpoint:sub.endpoint})});
    const j2=await r2.json();return !!(j2&&j2.ok);
  }catch(e){return false;}
}
async function probarPush(){
  try{
    await suscribirPush();
    const r=await fetch('/api/push/probar',{credentials:'same-origin'});const j=await r.json();
    if(!j||j.ok===false){alert('No se pudo enviar la prueba.');return;}
    const env=j.data&&j.data.enviados||0;const cod=(j.data&&j.data.codigos)||[];
    if(!env){alert('Este dispositivo todavía no está suscripto al push. Recargá la app una vez y volvé a probar.');return;}
    alert('Envié '+env+' aviso(s) de prueba a tus dispositivos'+(cod.length?(' (respuesta del servicio: '+cod.join(', ')+')'):'')+'. Fijate en las notificaciones del celular.');
  }catch(e){alert('No se pudo enviar la prueba: '+e.message);}
}
async function activarNotificaciones(){
  if(!('Notification' in window)||!('serviceWorker' in navigator)){alert('Este dispositivo o navegador no permite notificaciones. En iPhone, primero instalá ÁPICE en la pantalla de inicio desde Safari.');return;}
  let p;try{p=await Notification.requestPermission();}catch(e){p=Notification.permission;}
  if(p==='granted'){const ok=await suscribirPush();notificarUrgentes();alert(ok?'¡Listo! Vas a recibir los avisos en este dispositivo, incluso con la app cerrada.':'Notificaciones activadas. Para que lleguen con la app cerrada en iPhone, instalá ÁPICE en la pantalla de inicio desde Safari.');render();}
  else alert('No se activaron las notificaciones. Podés habilitarlas desde los ajustes del navegador/celular.');
}
async function notificarUrgentes(){
  try{
    if(!('Notification' in window)||Notification.permission!=='granted'||!('serviceWorker' in navigator))return;
    const reg=await navigator.serviceWorker.ready;const hoy=hoyKey();
    let vistos={};try{vistos=JSON.parse(localStorage.getItem('apice_notif_vistos')||'{}');}catch(e){}
    Object.keys(vistos).forEach(k=>{if(vistos[k]!==hoy)delete vistos[k];});
    const items=[];
    caducidadesProximas().filter(x=>x.nivel==='venc'||x.nivel==='rojo').forEach(x=>{items.push({key:'cad_'+x.cid,title:'⏰ Vencimiento de plazo',body:(x.dias<0?'Caducidad vencida':'Caducidad en '+x.dias+' días')+': '+x.caratula});});
    urgentesHoyManana().forEach(a=>{const esHoy=a.fecha===hoy;items.push({key:'aud_'+a.fecha+(a.hora||'')+(a.cliente||''),title:esHoy?'📅 Audiencia/cita HOY':'📅 Audiencia/cita mañana',body:(a.tipo==='cita'?('Cita con '+(a.cliente||'el cliente')):'Audiencia')+(a.hora?(' · '+a.hora+' hs'):'')});});
    for(const it of items){if(vistos[it.key]===hoy)continue;vistos[it.key]=hoy;try{await reg.showNotification(it.title,{body:it.body,icon:'/icon-192.png',badge:'/icon-192.png',tag:it.key,requireInteraction:false});}catch(e){}}
    try{localStorage.setItem('apice_notif_vistos',JSON.stringify(vistos));}catch(e){}
  }catch(e){}
}
function updateNotifBell(){const b=document.getElementById('sbnBadge'),btn=document.getElementById('sbNotif');if(!b||!btn)return;const n=notifs().length+citasProx().length+totalNuevos()+totalAlertas()+pagosInformados().length+caducidadesProximas().length+morosos().length+compartidasConmigo().length+(iusDesactualizado()?1:0)+__avAuto.docs+__avAuto.clis;b.textContent=n||'';b.style.display=n?'inline-flex':'none';btn.classList.toggle('on',(st.nav==='avisos'));btn.classList.toggle('hasn',n>0);}
