    const hoy=a.fecha===hk;const manana=(()=>{const d=new Date();d.setDate(d.getDate()+1);return a.fecha===(d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')+'-'+String(d.getDate()).padStart(2,'0'));})();
    const tag=hoy?'<span class="avi-tag hoy">HOY</span>':manana?'<span class="avi-tag man">MAÑANA</span>':'';
