function verEnCalendario(key){sideSt.sec='calendario';sideSt.calSel=key;const dt=new Date(key+'T00:00:00');sideSt.calY=dt.getFullYear();sideSt.calM=dt.getMonth();st.nav='calendario';window.scrollTo(0,0);render();}

/* ----- Audiencias ----- */
function renderAudiencias(){
  const cont=document.getElementById('sideContent');if(!cont)return;
  if(!sideSt.af)sideSt.af={tipo:'juzgado',fecha:'',hora:'',causa:'',detalle:'',cli:'',mat:'Derecho de familia',cliAsiste:false,modal:'presencial',lugar:'',link:'',lugarManual:false};
  const af=sideSt.af;
  const causasOpts=causas.map(c=>`<option value="${c.id}" ${af.causa===c.id?'selected':''}>${esc(cShort(c.caratula))}</option>`).join('');
  let cond;
  if(af.tipo==='juzgado'){
    cond=`<div class="calc-field"><label>Causa</label><select id="aud_causa" onchange="afSet('causa',this.value)"><option value="">— Elegí la causa —</option>${causasOpts}</select></div>
       <div class="calc-field"><label>Detalle (opcional)</label><input type="text" id="aud_detalle" value="${attr(af.detalle)}" placeholder="Ej. Audiencia preliminar (art. 360)" oninput="afSet('detalle',this.value)"></div>`;
  } else if(af.tipo==='cita'){
    const cliList=[...new Set(causas.map(c=>c.cliente).filter(Boolean))];
    cond=`<div class="calc-field"><label>Cliente</label><input type="text" id="aud_cli" list="aud_clilist" value="${attr(af.cli)}" placeholder="Nombre del cliente" oninput="afSet('cli',this.value)"><datalist id="aud_clilist">${cliList.map(n=>`<option value="${attr(n)}"></option>`).join('')}</datalist></div>
       <div class="calc-field"><label>Modalidad</label><select id="aud_modal" onchange="afSet('modal',this.value)"><option value="presencial" ${af.modal!=='virtual'?'selected':''}>Presencial</option><option value="virtual" ${af.modal==='virtual'?'selected':''}>Virtual</option></select></div>
       ${af.modal==='virtual'
         ? `<div class="calc-field"><label>Enlace de la videollamada</label><input type="text" id="aud_link" value="${attr(af.link||'')}" placeholder="Pegá el link (Meet, Zoom, etc.)" oninput="afSet('link',this.value)"></div>`
         : `<div class="calc-field"><label>Lugar</label><input type="text" id="aud_lugar" value="${attr(af.lugarManual?(af.lugar||''):((config.perfil&&config.perfil.domicilio)||''))}" placeholder="Dirección u oficina del estudio" oninput="afLugarManual(this.value)"><div class="calc-hint2">Se completa con el domicilio del estudio. Podés editarlo.</div></div>`}
       <div class="calc-field"><label>Nota (opcional)</label><input type="text" id="aud_detalle" value="${attr(af.detalle)}" placeholder="Motivo de la reunión" oninput="afSet('detalle',this.value)"></div>`;
  } else {
    cond=`<div class="calc-field"><label>Cliente</label><input type="text" id="aud_cli" value="${attr(af.cli)}" placeholder="Nombre del cliente" oninput="afSet('cli',this.value)"></div>
       <div class="calc-field"><label>Materia</label><input type="text" id="aud_mat" value="${attr(af.mat)}" oninput="afSet('mat',this.value)"></div>`;
  }
  const up=audiencias.slice().sort((a,b)=>((a.fecha||'')+(a.hora||'')).localeCompare((b.fecha||'')+(b.hora||'')));
  const listHtml=up.length?up.map(audItem).join(''):`<div class="vacio" style="padding:12px 2px">Todavía no cargaste audiencias.</div>`;
  cont.classList.add('wide');
  cont.innerHTML=`<div class="side-sectit">Audiencias</div>
    <div class="side-secsub">Aparecen en el calendario. Las citas con clientes también se ven en el portal del cliente.</div>
    <div class="aud-2col">
      <div class="aud-left">
        <div class="calc-field"><label>Tipo</label><select id="aud_tipo" onchange="afSet('tipo',this.value)">
          <option value="juzgado" ${af.tipo==='juzgado'?'selected':''}>En juzgado</option>
          <option value="mediacion" ${af.tipo==='mediacion'?'selected':''}>Mediación</option>
          <option value="cita" ${af.tipo==='cita'?'selected':''}>Cita con cliente</option></select></div>
        <div class="calc-field"><label>Fecha</label><input type="date" id="aud_fecha" value="${attr(af.fecha)}" oninput="afSet('fecha',this.value)"></div>
        <div class="calc-field"><label>Hora</label><input type="time" id="aud_hora" value="${attr(af.hora)}" oninput="afSet('hora',this.value)"></div>
        ${cond}
        ${af.tipo!=='cita'?`<label class="aud-check"><input type="checkbox" id="aud_cliasiste" ${af.cliAsiste?'checked':''} onchange="afSet('cliAsiste',this.checked)"> <span>El cliente debe asistir a esta audiencia</span></label>`:''}
        <div class="aud-btns"><button class="calc-btn" onclick="addAudiencia()">${af.tipo==='cita'?'+ Agregar cita':'+ Agregar audiencia'}</button><button class="calc-btn ghost" onclick="afReset()">Limpiar</button></div>
      </div>
      <div class="aud-right">
        <div class="cal-right-h">Audiencias cargadas</div>
        <div class="aud-list">${listHtml}</div>
      </div>
    </div>`;
}
function afSet(k,v){sideSt.af[k]=v;if(k==='tipo'||k==='modal')renderSection();}
function afLugarManual(v){sideSt.af.lugar=v;sideSt.af.lugarManual=true;}
function afReset(){const t=(sideSt.af&&sideSt.af.tipo)||'juzgado';sideSt.af={tipo:t,fecha:'',hora:'',causa:'',detalle:'',cli:'',mat:'Derecho de familia',cliAsiste:false,modal:'presencial',lugar:'',link:'',lugarManual:false};renderSection();}
function addAudiencia(){
  const af=sideSt.af;
  if(!af.fecha){alert('Poné la fecha de la audiencia.');return;}
  const a={id:'aud-'+Date.now(),tipo:af.tipo,fecha:af.fecha,hora:af.hora||'',cliAsiste:!!af.cliAsiste};
  if(af.tipo==='juzgado'){
    if(!af.causa){alert('Elegí la causa.');return;}
    a.causaId=af.causa;a.detalle=af.detalle||'';
    const c=get(af.causa);
    if(c){a.cliente=c.cliente||'';c.bitacora.unshift({fecha:audFechaDMY(af.fecha),texto:'Audiencia en juzgado'+(af.hora?(' '+af.hora+' hs'):'')+(af.detalle?(' — '+af.detalle):'')+(a.cliAsiste?' (el cliente debe asistir)':'')+'.',nuevo:true});syncUltimo(c);}
  } else if(af.tipo==='cita'){
    if(!af.cli){alert('Poné el nombre del cliente.');return;}
    a.cliente=af.cli;a.modalidad=(af.modal==='virtual'?'virtual':'presencial');
    if(a.modalidad==='virtual'){const le=document.getElementById('aud_link');a.link=le?le.value:(af.link||'');}
    else {const ge=document.getElementById('aud_lugar');a.lugar=ge?ge.value:((config.perfil&&config.perfil.domicilio)||'');}
    a.detalle=af.detalle||'';
  } else {
    a.cliente=af.cli||'';a.materia=af.mat||'Derecho de familia';
  }
  audiencias.push(a);persistAud();persist();
  const wasCausa=a.causaId;
  sideSt.af={tipo:af.tipo,fecha:'',hora:'',causa:'',detalle:'',cli:'',mat:'Derecho de familia',cliAsiste:false,modal:(af.modal||'presencial'),lugar:'',link:'',lugarManual:false};
  if(st.vista==='ficha'&&st.actual===wasCausa)renderFicha();
  renderSection();
}
function delAudiencia(id){audiencias=audiencias.filter(a=>a.id!==id);persistAud();renderSection();}

/* ----- Tareas (pendientes de todas las causas) ----- */
function renderTareas(){
  const cont=document.getElementById('sideContent');if(!cont)return;
  cont.classList.add('wide');
  /* #3 — mostramos TODAS: las hechas quedan tachadas y se borran con la × */
  let groups='';
  causas.forEach(c=>{
    const items=c.pendientes.map((p,i)=>({p,i}));
    if(!items.length)return;
    items.sort((a,b)=>{if(!!a.p.done!==!!b.p.done)return a.p.done?1:-1;return ((a.p.fecha||'9999-99')+'').localeCompare((b.p.fecha||'9999-99')+'');});
    const k=cc(c.estado);
    groups+=`<div class="tarea-grp"><button class="tg-h" onclick="abrirFicha('${c.id}')"><span class="tg-dot ${k}"></span><span class="tg-car">${esc(c.caratula)}</span><span class="tg-go">Ver causa ›</span></button>`+
      items.map(o=>{const f=o.p.fecha,done=o.p.done;
        const chip=f?`<span class="tt-date ${f<hoyKey()&&!done?'venc':(f===hoyKey()?'hoy':'')}">${audFechaDMY(f)}</span>`:'';
        const stTxt=done?'text-decoration:line-through;color:#9aa1ab':'';
        const stChk=done?'background:#15803D;color:#fff;border-color:#15803D':'';
        return `<div class="tarea-it"><div class="tcheck" style="${stChk}" onclick="toggleTarea('${c.id}',${o.i})" title="${done?'Marcar como no hecha':'Marcar como hecha'}"></div><div class="ttxt" style="${stTxt}" onclick="abrirFicha('${c.id}')">${esc(o.p.t)}</div>${chip}<span class="pdel" style="margin-left:auto;cursor:pointer;padding:0 6px" onclick="delTareaGlobal('${c.id}',${o.i})" title="Eliminar">×</span></div>`;
      }).join('')+`</div>`;
  });
  cont.innerHTML=`<div class="side-sectit">Tareas</div>
    <div class="side-secsub">Son los pendientes de todas las causas. Al tildarlas quedan <b>tachadas</b> (no desaparecen); para borrarlas, tocá la ×.</div>
    ${groups?`<div class="tareas-grid">${groups}</div>`:`<div class="vacio" style="padding:14px 2px">No tenés tareas cargadas.</div>`}`;
}
function toggleTarea(id,i){const c=get(id);if(c&&c.pendientes[i]){c.pendientes[i].done=!c.pendientes[i].done;persist();}if(st.vista==='ficha'&&st.actual===id)renderFicha();renderSection();}
function delTareaGlobal(id,i){const c=get(id);if(c&&c.pendientes[i]){c.pendientes.splice(i,1);persist();}if(st.vista==='ficha'&&st.actual===id)renderFicha();renderSection();}
/* ===== MÓDULO CLIENTES (v21) ===== */
const CLI='gestor_cli_v1';
let clientes={};
async function loadCli(){try{if(window.storage){const r=await window.storage.get(CLI);if(r&&r.value)return JSON.parse(r.value);}}catch(e){}try{if(typeof localStorage!=='undefined'){const v=localStorage.getItem(CLI);if(v)return JSON.parse(v);}}catch(e){}return null;}
async function saveCli(){const d=JSON.stringify(clientes);try{if(window.storage){await window.storage.set(CLI,d);return;}}catch(e){}try{if(typeof localStorage!=='undefined')localStorage.setItem(CLI,d);}catch(e){}}
function persistCli(){saveCli();}
function encName(n){return encodeURIComponent(n).replace(/'/g,'%27');}
function clienteNombres(){const set=new Set();causas.forEach(c=>{if(c.cliente&&c.cliente!=='A completar')set.add(c.cliente);});Object.keys(clientes).forEach(k=>set.add(k));return [...set];}
function causasDe(n){return causas.filter(c=>c.cliente===n);}
function cliInitials(n){const p=(n||'').replace(/[,.]/g,' ').trim().split(/\s+/).filter(Boolean);const s=((p[0]||'')[0]||'')+((p[1]||'')[0]||'');return s.toUpperCase()||'C';}
function cliSearch(v){st.cliQ=v;renderClientes();const el=document.getElementById('cliq');if(el){el.focus();el.setSelectionRange(el.value.length,el.value.length);}}
