function renderReportes(){
  if(repSt.exp){renderRepActividad(repSt.exp);return;}
  const subs=[['estudio','Mi Estudio'],['expedientes','Mis Expedientes'],['honorarios','Honorarios'],['recibos','Libro de Recibos'],['clientes','Clientes'],['productividad','Productividad']];
  const titulos={estudio:'Mi Estudio',expedientes:'Expedientes que requieren atención',honorarios:'Informe de Honorarios',recibos:'Libro de Recibos',clientes:'Reporte de Clientes',productividad:'Productividad'};
  let body;
  switch(repSt.sec){case 'expedientes':body=repExpedientes();break;case 'honorarios':body=repHonorarios();break;case 'recibos':body=repRecibos();break;case 'clientes':body=repClientes();break;case 'productividad':body=repProductividad();break;default:body=repEstudio();}
  document.getElementById('app').innerHTML=`<div class="tool-wrap wide" id="repWrap">
    <div class="main-head"><div><div class="eyebrow">Reportes</div><h1>${titulos[repSt.sec]||'Reportes'}</h1><div class="mh-sub">Calculado con tus datos cargados · ${hoyTxt()}</div></div>
      <div class="rep-exports"><button class="btn-sec" onclick="repExportPDF()">⭳ PDF</button><button class="btn-sec" onclick="repExportXLS()">⭳ Excel</button></div></div>
    <div class="rep-subnav">${subs.map(s=>`<button class="rep-sub ${repSt.sec===s[0]?'on':''}" onclick="repNav('${s[0]}')">${s[1]}</button>`).join('')}</div>
    <div class="rep-body">${body}</div></div>`;
}
/* ===== MÓDULO CONFIGURACIÓN (v25) ===== */
function cfgDefaults(){
  if(!config.perfil)config.perfil={estudio:'Estudio Jurídico Rocío Luján',abogada:'Dra. Rocío Cristal Luján',matricula:'',fuero:'Familia',domicilio:'Catamarca, Provincia de Catamarca',cuit:'',telefono:'',email:''};
  if(config.repInactiv==null)config.repInactiv=30;
  if(config.repVenc==null)config.repVenc=15;
  if(config.alertaDias==null)config.alertaDias=10;
  if(config.iusFecha==null)config.iusFecha='';
  if(config.feriaJulioDesde==null)config.feriaJulioDesde='';
  if(config.feriaJulioHasta==null)config.feriaJulioHasta='';
  ferMigrate();
  if(config.pin===undefined)config.pin=null;
  if(config.reciboSeq==null)config.reciboSeq=1;
  if(!config.escalaHon)config.escalaHon={};
  if(!config.profesionales){const pp=config.perfil||{};config.profesionales=[{nombre:pp.abogada||'Dra. Roc\u00edo Cristal Luj\u00e1n',mp:pp.matricula||'2686',cuit:pp.cuit||''}];}
  if(config.perfil&&config.perfil.estudio==='Estudio Jur\u00eddico Roc\u00edo Luj\u00e1n')config.perfil.estudio='Estudio Jur\u00eddico';
  if(config.perfil&&!config.perfil.matricula)config.perfil.matricula='2686';
}
function cfgAvatar(){const el=document.getElementById('avatarInput');if(el)el.click();}
function abogados(){const pl=(config.profesionales||[]).map(p=>p.nombre).filter(Boolean);if(pl.length)return pl;const a=(config&&config.abogados&&config.abogados.length)?config.abogados.slice():[];if(!a.length)a.push((config&&config.perfil&&config.perfil.abogada)||'Dra. Rocío Cristal Luján');return a;}
function descargarJSON(nombre,obj){try{const blob=new Blob([JSON.stringify(obj,null,2)],{type:'application/json'});const url=URL.createObjectURL(blob);const a=document.createElement('a');a.href=url;a.download=nombre;document.body.appendChild(a);a.click();a.remove();URL.revokeObjectURL(url);}catch(e){alert('La exportación funciona en el navegador (no en la vista previa).');}}
/* Copia de seguridad COMPLETA (v46): suma la Guía Judicial y el listado de
   documentos guardados en el servidor, para que el respaldo sirva de verdad. */
async function exportarDatos(){
  try{syncAviso('warn','Generando la copia de seguridad…');}catch(e){}
  const documentosServidor=[];
  for(const c of (causas||[])){
    try{
      const r=await fetch('/api/archivos?causa='+encodeURIComponent(c.id),{credentials:'same-origin'});
      const j=await r.json();
      ((j&&j.data)||[]).forEach(a=>documentosServidor.push({causa:c.caratula,causa_id:c.id,archivo_id:a.id,nombre:a.nombre,tipo:a.tipo,tamano:a.tamano,fecha_doc:a.fecha_doc,visible_cliente:a.visible_cliente}));
    }catch(e){}
  }
  descargarJSON('apice-respaldo-'+hoyKey()+'.json',{
    generado:new Date().toISOString(),
    version:' APICE respaldo v2',
    contiene:'Causas (con movimientos, honorarios, pendientes y documentos-ficha), clientes, agenda, Guia Judicial y configuracion.',
    aclaracion:'Los ARCHIVOS de los documentos no estan dentro de este JSON: se guardan en el servidor. En "documentosServidor" va el listado completo con nombre, fecha y causa para poder ubicarlos.',
    causas,clientes,audiencias,directorio,config,documentosServidor
  });
  try{syncAviso('ok','✓ Copia de seguridad descargada ('+(causas||[]).length+' causas, '+documentosServidor.length+' documentos listados).');}catch(e){}
}
/* Export legible en planilla: una fila por causa. */
function exportarCausasCSV(){
  const filas=[['Caratula','Cliente','Expediente','Estado','Fuero','Juzgado','Secretaria','Materia','Movimientos','Ultimo movimiento','Fecha ultimo']];
  (causas||[]).forEach(c=>{
    const b=(c.bitacora||[])[0]||{};
    filas.push([c.caratula||'',c.cliente||'',c.expediente||'',(ESTADOS[c.estado]||{}).l||c.estado||'',c.fuero||'',c.juzgado||'',c.secretaria||'',(c.materia||[]).join(' / '),(c.bitacora||[]).length,b.texto||'',b.fecha||'']);
  });
  descargarCSV('apice-causas-'+hoyKey()+'.csv',filas);
}
/* restablecerDatos() se eliminó por seguridad (v46): cargaba los datos de
   ejemplo y los guardaba, lo que podía pisar causas reales del estudio.
   Era del tiempo del prototipo y ya no tenía ningún botón que la usara. */
function profRowsHTML(){const list=config.profesionales||[];if(!list.length)return '';return '<div class="prof-list">'+list.map((p,i)=>`<div class="prof-row"><input id="pf_nom_${i}" placeholder="Nombre (Dra./Dr. \u2026)" value="${attr(p.nombre||'')}"><input id="pf_mp_${i}" placeholder="M.P." value="${attr(p.mp||'')}"><input id="pf_cuit_${i}" placeholder="CUIL / CUIT" value="${attr(p.cuit||'')}"><button class="prof-del" onclick="profDel(${i})" title="Quitar">\u2715</button></div>`).join('')+'</div>';}
function profReadRows(){const list=[];let i=0;while(document.getElementById('pf_nom_'+i)){list.push({nombre:document.getElementById('pf_nom_'+i).value.trim(),mp:document.getElementById('pf_mp_'+i).value.trim(),cuit:document.getElementById('pf_cuit_'+i).value.trim()});i++;}if(i>0)config.profesionales=list;}
function profAddRow(){profReadRows();config.profesionales=config.profesionales||[];config.profesionales.push({nombre:'',mp:'',cuit:''});renderConfig();}
function profDel(i){profReadRows();config.profesionales.splice(i,1);if(!config.profesionales.length)config.profesionales.push({nombre:'',mp:'',cuit:''});renderConfig();}
function profQuitarLogo(){if(!confirm('\u00bfQuitar el logo del estudio?'))return;config.avatar='';saveConfig();updateAvatar();renderConfig();}
function guardarConfig(){
  const v=id=>{const e=document.getElementById(id);return e?e.value.trim():'';};
  const num=(id,def)=>{const e=document.getElementById(id);const n=e?parseInt(e.value,10):NaN;return isNaN(n)?def:Math.max(0,n);};
  config.perfil={estudio:v('cfg_estudio'),fuero:v('cfg_fuero'),domicilio:v('cfg_dom'),telefono:v('cfg_tel'),email:v('cfg_mail')};profReadRows();{const p0=(config.profesionales||[])[0]||{};config.perfil.abogada=p0.nombre||'';config.perfil.matricula=p0.mp||'';config.perfil.cuit=p0.cuit||'';}escReadRows();
  const iusN=parseMiles((document.getElementById('cfg_ius')||{}).value);if(!isNaN(iusN)&&iusN>0)config.valorIUS=iusN;
  config.iusFecha=v('cfg_iusf');
  config.feriaJulioDesde=v('cfg_fjd');config.feriaJulioHasta=v('cfg_fjh');
  config.alertaDias=num('cfg_alerta',10);

  config.repInactiv=num('cfg_inact',30);
  config.repVenc=num('cfg_venc',15);
  saveConfig();updateAvatar();
  const btn=document.getElementById('cfgSaveBtn');if(btn){btn.textContent='✓ Guardado';setTimeout(()=>{const b=document.getElementById('cfgSaveBtn');if(b)b.textContent='Guardar cambios';},1600);}
}
