const CIMA_AV=`<svg class="cimaStarSvg" viewBox="0 0 48 48" xmlns="http://www.w3.org/2000/svg" role="img" aria-label="Cima"><defs><linearGradient id="cimatg" x1="0" y1="0" x2="1" y2="1"><stop offset="0" stop-color="#3FC8BD"/><stop offset="1" stop-color="#356E94"/></linearGradient></defs><circle cx="24" cy="24" r="22" fill="none" stroke="#7FB0C4" stroke-width="1.5" opacity=".55"/><path d="M24 4 L28.5 18.5 L43 23 L28.5 27.5 L24 42 L19.5 27.5 L5 23 L19.5 18.5 Z" fill="url(#cimatg)"/><path d="M24 13 L26.6 21.4 L35 24 L26.6 26.6 L24 35 L21.4 26.6 L13 24 L21.4 21.4 Z" fill="#8DE6DD" opacity=".85"/><path class="cimaTw" d="M37 8 C37 11 39 13 42 13 C39 13 37 15 37 18 C37 15 35 13 32 13 C35 13 37 11 37 8 Z" fill="#EAFCFF"/></svg>`;
let cimaSt={open:false,node:'root',log:[]};
function cimaIsMobile(){return window.innerWidth<760;}
function cimaTxt(s){const m=cimaIsMobile();return s.replace(/%menu%/g,m?'abrí el menú con ☰ y ':'').replace(/%clic%/g,m?'tocá':'hacé clic').replace(/%Clic%/g,m?'Tocá':'Hacé clic');}
function cimaFmt(raw){let t=esc(cimaTxt(raw));return t.replace(/\*\*(.+?)\*\*/g,'<b>$1</b>');}
function cimaPush(who,html){cimaSt.log.push({who,html});}
function cimaBot(node){(CIMA[node]||CIMA.root).m.forEach(m=>cimaPush('bot',cimaFmt(m)));}
function injectCima(){
  if(document.getElementById('cimaBtn'))return;
  const wrap=document.createElement('div');wrap.id='cimaWrap';
  wrap.innerHTML=`<button id="cimaBtn" onclick="cimaToggle()" title="Ayuda de ÁPICE" aria-label="Ayuda">${CIMA_AV}</button>
    <div id="cimaPanel" class="cima-panel" style="display:none">
      <div class="cima-head"><div class="cima-h-id"><span class="cima-star">${CIMA_AV}</span><div><div class="cima-h-n">Cima</div><div class="cima-h-s">Tu guía en ÁPICE</div></div></div>
        <div class="cima-h-acc"><button onclick="cimaReset()" title="Volver al inicio">⟲</button><button onclick="cimaToggle()" title="Cerrar">✕</button></div></div>
      <div class="cima-body" id="cimaBody"></div>
      <div class="cima-foot">Guía paso a paso · no reemplaza asesoramiento legal</div>
    </div>`;
  document.body.appendChild(wrap);
}
function cimaToggle(){cimaSet(!cimaSt.open);}
function cimaSet(open){
  cimaSt.open=open;
  const p=document.getElementById('cimaPanel'),b=document.getElementById('cimaBtn');
  if(p)p.style.display=open?'flex':'none';
  if(b)b.classList.toggle('open',open);
  if(open&&!cimaSt.log.length){cimaSt.node='root';cimaBot('root');}
  if(open)renderCima();
}
function cimaReset(){cimaSt.log=[];cimaSt.node='root';cimaBot('root');renderCima();}
function cimaPick(i){
  const node=CIMA[cimaSt.node]||CIMA.root;const o=node.o[i];if(!o)return;
  cimaPush('user',esc(o.t));
  if(o.nav){cimaSt.node='root';cimaPush('bot','Te llevo ahí. Cuando quieras, seguimos. ✦');navTo(o.nav);cimaBot('root');if(cimaIsMobile())cimaSet(false);else{cimaSt.open=true;renderCima();}return;}
  const go=o.menu?'root':(o.human?'human':o.go);
  cimaSt.node=go;cimaBot(go);renderCima();
}
function renderCima(){
  const body=document.getElementById('cimaBody');if(!body)return;
  const node=CIMA[cimaSt.node]||CIMA.root;
  const bubbles=cimaSt.log.map(e=>`<div class="cima-row ${e.who}"><div class="cima-bub ${e.who}">${e.html}</div></div>`).join('');
  const opts=`<div class="cima-opts">${node.o.map((o,i)=>`<button class="cima-opt" onclick="cimaPick(${i})">${esc(o.t)}</button>`).join('')}</div>`;
  body.innerHTML=bubbles+opts;
  body.scrollTop=body.scrollHeight;
}
/* ===== LEGALES (v29) — textos consultables dentro de la app ===== */
const LEGAL={
 terminos:`<h4>Términos y Condiciones — Perfil Profesional</h4>
  <p>Al aceptar e ingresar, el/la profesional o estudio (el "Usuario Profesional") declara haber leído y aceptado estos Términos, y ser <b>abogado/a matriculado/a o estudio legalmente constituido</b> con capacidad para obligarse.</p>
  <h4>1. Naturaleza del servicio</h4>
  <p>ÁPICE es una herramienta de <b>gestión y soporte operativo</b> del ejercicio profesional. <b>No presta servicios jurídicos, no emite dictámenes ni representa a persona alguna</b>, y no sustituye el criterio del profesional. La relación de asesoramiento subsiste con exclusividad entre el Usuario Profesional y sus clientes.</p>
  <h4>2. Límite de responsabilidad por automatización e IA</h4>
  <p>Todo resultado automatizado —cálculos de plazos, semáforos, informes y las funciones de EstrategIA— es <b>orientativo, preliminar y no vinculante</b>. ÁPICE no garantiza ausencia de errores ni desactualizaciones. Es obligación <b>exclusiva del Usuario</b> revisar y validar todo contenido contra las fuentes oficiales antes de presentarlo o comunicarlo. ÁPICE no responde por daños derivados de la confianza en resultados no validados, en la máxima medida permitida por la ley.</p>
  <h4>3. Secreto profesional, roles e indemnidad</h4>
  <p>El Usuario Profesional es el <b>Responsable del Tratamiento</b> de los datos de sus clientes; ÁPICE actúa como <b>Encargado</b>, según sus instrucciones. El Usuario garantiza contar con base legal para cargar los datos y mantiene indemne a ÁPICE por la falta de autorización del cliente o por el mal uso, pérdida o préstamo de credenciales. La indemnidad no alcanza el dolo o la culpa grave de ÁPICE.</p>
  <h4>4. Datos disociados para mejora y entrenamiento</h4>
  <p>El Usuario podrá autorizar —de forma <b>separada y revocable</b>— que ÁPICE genere <b>datos disociados y anonimizados de forma irreversible</b> y los use para entrenar y mejorar sus modelos. La licencia recae sobre esos datos disociados, nunca sobre datos personales identificables. Los datos sensibles y de niños, niñas y adolescentes no se usan para entrenamiento.</p>
  <h4>5. Tope de responsabilidad</h4>
  <p>En la máxima medida legal, la responsabilidad total de ÁPICE se limita al monto abonado en los 12 meses previos al hecho, salvo dolo o culpa grave y derechos irrenunciables.</p>
  <h4>6. Ley aplicable</h4>
  <p>Estos Términos se rigen por las leyes de la República Argentina.</p>`,
 privacidad:`<h4>Política de Privacidad</h4>
  <p>Esta Política rige el tratamiento de datos personales en ÁPICE. Marco: Ley 25.326 y Decreto 1558/2001; autoridad de control: AAIP.</p>
  <h4>1. Doble rol de ÁPICE</h4>
  <p>ÁPICE es <b>Responsable</b> de los datos de la <b>cuenta del profesional</b> (registro, facturación, uso), y <b>Encargado</b> de los <b>datos de clientes y causas</b> que el profesional carga, tratándolos según sus instrucciones.</p>
  <h4>2. Datos que tratamos</h4>
  <p>De la cuenta: nombre, matrícula, contacto, facturación y registros técnicos de uso. De las causas: datos de clientes y partes, expedientes, documentos, honorarios, agenda y plazos (pueden incluir datos sensibles).</p>
  <h4>3. Finalidades y base legal</h4>
  <p>Prestar el servicio (ejecución del contrato), gestión y facturación, soporte, seguridad, y —solo con datos disociados y consentimiento separado— mejora y entrenamiento de modelos.</p>
  <h4>4. IA y disociación</h4>
  <p>Las funciones automatizadas son orientativas y sujetas a revisión humana. El entrenamiento se realiza exclusivamente sobre datos <b>anonimizados de forma irreversible</b>.</p>
  <h4>5. Seguridad y conservación</h4>
  <p>Medidas razonables (cifrado, control de accesos, respaldo). Los datos se conservan mientras dure la relación y por los plazos legales; luego se devuelven o suprimen según instruya el profesional.</p>
  <h4>6. Derechos del titular</h4>
  <p>Acceso, rectificación, actualización y supresión. Los datos de causas se canalizan por el abogado (Responsable); los de cuenta, ante ÁPICE.</p>
  <p style="font-size:11.5px;color:var(--mut)"><i>El titular puede ejercer el derecho de acceso en forma gratuita a intervalos no inferiores a seis meses (art. 14 inc. 3, Ley 25.326). La AAIP, órgano de control, atiende denuncias por incumplimiento de las normas de protección de datos.</i></p>`,
 cookies:`<h4>Política de Cookies</h4>
  <p>Las cookies y tecnologías similares (incluido el almacenamiento local del navegador) permiten el funcionamiento y la mejora de la Plataforma.</p>
  <h4>Tipos</h4>
  <ul>
    <li><b>Estrictamente necesarias:</b> sesión, seguridad y almacenamiento local de la app. No requieren consentimiento.</li>
    <li><b>Funcionales:</b> recordar preferencias (tema, configuración). Con consentimiento.</li>
    <li><b>Analíticas:</b> métricas de uso agregadas para mejorar. Con consentimiento.</li>
  </ul>
  <p><b>Nota:</b> en su versión actual, ÁPICE usa principalmente <b>almacenamiento local del dispositivo</b>. Las cookies analíticas y de terceros se incorporan en la versión conectada, con su banner de consentimiento.</p>
  <h4>Gestión</h4>
  <p>Podés aceptar o rechazar las cookies no necesarias y cambiar tu elección en cualquier momento. El rechazo no impide usar las funciones esenciales.</p>`
};
Object.assign(LEGAL,{
 dpa:`<h4>Acuerdo de Encargo de Tratamiento (DPA)</h4><p>Regula el tratamiento que ÁPICE (<b>Encargado</b>) realiza por cuenta del profesional (<b>Responsable</b>) sobre los datos de clientes y causas (art. 25, Ley 25.326).</p><h4>Instrucciones</h4><p>ÁPICE trata los datos solo según las instrucciones del Responsable y las finalidades del servicio; no los usa para fines propios, salvo la generación de datos disociados irreversibles previamente consentida.</p><h4>Confidencialidad y seguridad</h4><p>Deber de confidencialidad que subsiste tras finalizar el acuerdo, y medidas técnicas: cifrado, control de accesos, respaldo y minimización del acceso.</p><h4>Sub-encargados</h4><p>Se admiten proveedores (alojamiento, mensajería, analítica) obligados a deberes equivalentes; ÁPICE responde por su actuación.</p><h4>Asistencia e incidentes</h4><p>ÁPICE asiste al Responsable en el ejercicio de derechos de los titulares y notifica sin demora indebida los incidentes de seguridad.</p><h4>Devolución o supresión</h4><p>Finalizada la relación, los datos se devuelven o suprimen a elección del Responsable, salvo obligación legal de conservación.</p>`,
 incidentes:`<h4>Protocolo de Incidentes de Seguridad</h4><p>Incidente: toda vulneración que cause destrucción, pérdida, alteración, acceso no autorizado o divulgación indebida de datos personales.</p><h4>Detección y contención</h4><p>Se contiene el incidente, se evalúa su alcance (datos y personas afectadas) y se documenta en un registro interno.</p><h4>Notificación</h4><p>Al profesional (Responsable): sin demora indebida, con objetivo de 72 horas. A la autoridad de control (AAIP) y a los titulares: cuando corresponda según el riesgo, en colaboración con el Responsable.</p><h4>Contenido mínimo</h4><p>Naturaleza del incidente, categorías y volumen de datos y personas afectadas, consecuencias probables, medidas adoptadas y datos de contacto.</p><h4>Mejora continua</h4><p>Cada incidente se registra con su análisis de causa raíz y las medidas correctivas para prevenir su repetición.</p>`
});
function legalTab(t){st.modal.tab=t;render();}
function mLegal(){
  const tab=(st.modal&&st.modal.tab)||'terminos';
  const tabs=[['terminos','Términos'],['privacidad','Privacidad'],['cookies','Cookies'],['dpa','DPA'],['incidentes','Incidentes']];
  const nav=tabs.map(([k,l])=>`<button class="legal-tab ${tab===k?'on':''}" onclick="legalTab('${k}')">${l}</button>`).join('');
  return `<div class="modal modal-legal"><h3>Legales de ÁPICE</h3>
    <div class="legal-tabs">${nav}</div>
    <div class="legal-body">${LEGAL[tab]||LEGAL.terminos}</div>
    <div class="legal-foot">Versión 1.0 · Junio 2026 · Borrador para revisión profesional. Los datos de la empresa titular (razón social, CUIT, domicilio) se completarán al definirse.</div>
    <div class="legal-cierre"><button class="btn-add" onclick="closeModal()">Cerrar</button></div></div>`;
}
