/* ===== CALCULADORA DE PLAZOS — CPCyC Catamarca (Ley 2339) (v32) ===== */
function cpParse(s){if(!/^\d{4}-\d{2}-\d{2}$/.test(s||''))return null;const a=s.split('-').map(Number);const dt=new Date(a[0],a[1]-1,a[2]);return isNaN(dt.getTime())?null:dt;}
function cpDOW(dt){return ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'][dt.getDay()];}
function cpFmt(dt){const dd=String(dt.getDate()).padStart(2,'0'),mm=String(dt.getMonth()+1).padStart(2,'0');return cpDOW(dt)+' '+dd+'/'+mm+'/'+dt.getFullYear();}
function cpMD(dt){return (dt.getMonth()+1)*100+dt.getDate();}
function cpInFeria(dt,feria){if(!feria)return false;if(dt.getMonth()===0)return true;const ds=cpParse(config.feriaJulioDesde),dh=cpParse(config.feriaJulioHasta);if(ds&&dh){const k=cpMD(dt),a=cpMD(ds),b=cpMD(dh);return a<=b?(k>=a&&k<=b):(k>=a||k<=b);}return false;}
function cpFeriado(dt){return !!ferMatch(dt);}
function cpHabil(dt,feria){const w=dt.getDay();if(w===0||w===6)return false;if(cpFeriado(dt))return false;if(cpInFeria(dt,feria))return false;return true;}
function cpNextHabil(dt,feria){const d=new Date(dt.getFullYear(),dt.getMonth(),dt.getDate());while(!cpHabil(d,feria))d.setDate(d.getDate()+1);return d;}
function cpCompute(fecha,dias,modo,feria){
  const f=cpParse(fecha);if(!f||!(dias>=1))return null;
  const start=new Date(f.getFullYear(),f.getMonth(),f.getDate()+1);
  let venc,primer;
  if(modo==='habiles'){let d=new Date(start),count=0;primer=cpNextHabil(start,feria);
    while(true){if(cpHabil(d,feria)){count++;if(count===dias){venc=new Date(d);break;}}d.setDate(d.getDate()+1);}
  } else {primer=new Date(start);venc=new Date(start);venc.setDate(venc.getDate()+(dias-1));}
  const vencHabil=cpHabil(venc,feria);
  const vencEf=(!vencHabil)?cpNextHabil(venc,feria):venc;
  const gracia=cpNextHabil(new Date(vencEf.getFullYear(),vencEf.getMonth(),vencEf.getDate()+1),feria);
  return {f,primer,venc,vencHabil,vencEf,gracia,trasladado:vencEf.getTime()!==venc.getTime()};
}
function cpPreset(sel){if(sel.value!=='custom'){const e=document.getElementById('cp_dias');if(e)e.value=sel.value;}cpUpdate();}
function cpUpdate(){
  const out=document.getElementById('cpResult');if(!out)return;
  const fecha=(document.getElementById('cp_fecha')||{}).value||'';
  const dias=parseInt((document.getElementById('cp_dias')||{}).value,10);
  const modo=(document.getElementById('cp_modo')||{}).value||'habiles';
  const feria=!!(document.getElementById('cp_feria')||{}).checked;
  const r=cpCompute(fecha,dias,modo,feria);
  if(!r){out.innerHTML='<div class="cp-empty">Cargá una fecha de notificación y la cantidad de días.</div>';return;}
  out.innerHTML=`<div class="cp-card">
    <div class="cp-line"><span>Plazo</span><b>${dias} días ${modo==='habiles'?'hábiles':'corridos'}</b></div>
    <div class="cp-line"><span>Notificación</span><b>${cpFmt(r.f)} <i>(no se cuenta)</i></b></div>
    <div class="cp-line"><span>Empieza a correr</span><b>${cpFmt(r.primer)}</b></div>
    <div class="cp-venc"><div class="cp-venc-l">Vence</div><div class="cp-venc-v">${cpFmt(r.vencEf)}</div>${r.trasladado?`<div class="cp-venc-n">El plazo terminaba el ${cpFmt(r.venc)} (inhábil); se traslada al primer día hábil.</div>`:''}</div>
    <div class="cp-gracia">⏱ Con el <b>plazo de gracia</b> (art. 124), un escrito puede presentarse válidamente dentro de las dos primeras horas hábiles del <b>${cpFmt(r.gracia)}</b>.</div>
    <div class="cad-warn">⚠ Cálculo orientativo según el CPCyC de Catamarca (Ley 2339, arts. 152 y 156). Verificá el plazo, los feriados y las ferias en el expediente y en la norma aplicable antes de actuar.</div>
  </div>`;
}
function renderCalcPlazos(){
  const today=new Date().toISOString().slice(0,10);
  document.getElementById('app').innerHTML=`<div class="tool-wrap" id="sideContent">
    <div class="side-sectit">Calculadora de plazos</div>
    <div class="side-secsub">Cómputo orientativo según el Código Procesal Civil y Comercial de Catamarca (Ley 2339). Los plazos corren en días hábiles desde el día siguiente a la notificación (arts. 152 y 156).</div>
    <div class="calc-field"><label>Tipo de plazo (atajo)</label><select id="cp_preset" onchange="cpPreset(this)">
      <option value="5">Traslado / vista (general) — 5 días</option>
      <option value="15">Contestación de demanda · ordinario — 15 días</option>
      <option value="5">Contestación · proceso sumarísimo — 5 días</option>
      <option value="3">Recurso de reposición — 3 días</option>
      <option value="5">Recurso de apelación — 5 días</option>
      <option value="10">Expresión de agravios — 10 días</option>
      <option value="custom">Personalizado</option>
    </select></div>
    <div class="calc-field"><label>Fecha de la notificación</label><input type="date" id="cp_fecha" value="${today}" onchange="cpUpdate()"></div>
    <div class="calc-2"><div class="calc-field"><label>Cantidad de días</label><input type="number" id="cp_dias" min="1" value="5" oninput="cpUpdate()"></div>
    <div class="calc-field"><label>Se cuentan en</label><select id="cp_modo" onchange="cpUpdate()"><option value="habiles">Días hábiles</option><option value="corridos">Días corridos</option></select></div></div>
    <label class="aud-check"><input type="checkbox" id="cp_feria" checked onchange="cpUpdate()"> <span>Descontar ferias judiciales (enero y julio)</span></label>
    <div id="cpResult" style="margin-top:6px"></div>
  </div>`;
  setTimeout(cpUpdate,0);
}
/* ===== BLOQUEO CON CLAVE (PIN) (v32) ===== */
function cpHash(s){let h=5381;s=String(s);for(let i=0;i<s.length;i++)h=((h<<5)+h+s.charCodeAt(i))>>>0;return 'h'+h;}
function injectLock(){if(document.getElementById('lock'))return;const el=document.createElement('div');el.id='lock';document.body.appendChild(el);renderLock('');}
function renderLock(err){const el=document.getElementById('lock');if(!el)return;
  el.innerHTML=`<div class="lock-scrim"></div><div class="lock-card">
    <div class="lock-logo">${APICE_LOGO}</div>
    <div class="lock-tit">Ingresá tu clave</div>
    <div class="lock-sub">Tu información está protegida en este dispositivo.</div>
    <input id="lockPin" type="password" inputmode="numeric" maxlength="12" placeholder="••••" onkeydown="if(event.key==='Enter')lockTry()">
    <button class="lock-btn" onclick="lockTry()">Desbloquear</button>
    ${err?`<div class="lock-err">${esc(err)}</div>`:''}
    <div class="lock-foot">Bloqueo local básico (Prototipo A): no cifra los datos. La seguridad por usuario llega con la versión conectada.</div>
  </div>`;
  setTimeout(()=>{const i=document.getElementById('lockPin');if(i)i.focus();},40);
}
function lockTry(){const i=document.getElementById('lockPin');const v=i?i.value:'';if(config.pin&&cpHash(v)===config.pin){const el=document.getElementById('lock');if(el)el.remove();}else{renderLock('Clave incorrecta. Probá de nuevo.');}}
function lockNow(){if(config.pin)injectLock();else alert('Primero activá el bloqueo con una clave en Configuración.');}
function setPin(){const e=document.getElementById('cfg_pin');const v=e?e.value.trim():'';if(v.length<4){alert('La clave debe tener al menos 4 caracteres.');return;}config.pin=cpHash(v);saveConfig();renderConfig();}
function removePin(){if(!confirm('¿Quitar el bloqueo con clave de este dispositivo?'))return;config.pin=null;saveConfig();renderConfig();}
/* ===== FERIADOS (v33) — modelo de objetos, editor y matching ===== */
function ferYMD(dt){return dt.getFullYear()+'-'+String(dt.getMonth()+1).padStart(2,'0')+'-'+String(dt.getDate()).padStart(2,'0');}
function ferMatch(dt){const list=config.feriados||[];const iso=ferYMD(dt);const md=iso.slice(5);for(let i=0;i<list.length;i++){const f=list[i];if(!f||!f.fecha)continue;if(f.anual){if(f.fecha.slice(5)===md)return f;}else if(f.fecha===iso)return f;}return null;}
