function dirIntParse(x){const i=x.lastIndexOf('— ');if(i>=0)return {lbl:x.slice(0,i).trim(),nom:x.slice(i+2).trim()};const j=x.indexOf(':');if(j>=0)return {lbl:x.slice(0,j).trim(),nom:x.slice(j+1).trim()};return {lbl:'',nom:x.trim()};}
