function dirGuessFuero(nombre){nombre=nombre||'';if(/violencia|familia/i.test(nombre))return 'Familia';if(/civil/i.test(nombre))return 'Civil';if(/trabajo|laboral/i.test(nombre))return 'Trabajo';if(/penal|correccional/i.test(nombre))return 'Penal';return '';}
function dirEsJuzgado(x){if(!x)return false;if(x.cat)return x.cat==='juzgado';return /^Juzgado\b/i.test(x.nombre||'');}
function dirJuzList(){if(!directorio||!directorio.length){try{seedDir();}catch(e){}}return (directorio||[]).filter(dirEsJuzgado);}
function dirMigrateCats(){try{const seed=DIR_SEED();const M={};seed.forEach(s=>{M[s.id]=s.cat;});let ch=false;(directorio||[]).forEach(e=>{if(e&&!e.cat){if(M[e.id])e.cat=M[e.id];else if(/^Juzgado\b/i.test(e.nombre||''))e.cat='juzgado';else if(/mediaci/i.test(e.nombre||''))e.cat='mediacion';else if(/mesa|notificacion|audiencia/i.test(e.nombre||''))e.cat='mesa';else if(/asesor/i.test(e.nombre||''))e.cat='asesoria';else if(/equipo/i.test(e.nombre||''))e.cat='equipo';else e.cat='colega';ch=true;}});if(ch)persistDir();}catch(e){}}
function dirNorm(s){return (s||'').toLowerCase().normalize('NFD').replace(/[̀-ͯ]/g,'');}
function dirNombreDe(id){if(!id)return '';const j=dirJuzList().find(x=>x.id===id);return j?j.nombre:'';}
function dirPickFilter(pfx){const inp=document.getElementById(pfx+'_dirq');const cont=document.getElementById(pfx+'_dirlist');if(!cont)return;const nq=dirNorm(inp?inp.value:'').trim();let arr=dirJuzList();if(nq)arr=arr.filter(j=>dirNorm(j.nombre+' '+(j.rol||'')+' '+dirGuessFuero(j.nombre)).indexOf(nq)>=0);if(!arr.length){cont.innerHTML='<div class="dpk-empty">Sin coincidencias. Probá otra palabra (familia, civil…). Si el juzgado no está en la Guía, escribilo a mano abajo.</div>';cont.style.display='block';return;}const selId=(document.getElementById(pfx+'_dirjuz')||{}).value||'';cont.innerHTML=arr.map(j=>'<button type="button" class="dpk-item'+(j.id===selId?' sel':'')+'" onclick="dirPickChoose(\''+pfx+'\',\''+j.id+'\')"><b>'+esc(j.nombre)+'</b><i>'+esc(j.rol||'')+'</i></button>').join('');cont.style.display='block';}
