/* ===== Botón "atrás" del navegador y del celular (v46) =====
   Antes, tocar "atrás" salía de ÁPICE aunque estuvieras dentro de una causa
   o con una ventana abierta. Ahora retrocede DENTRO de la app, como espera
   cualquiera que use un celular:
       ventana abierta  ->  la cierra
       ficha de causa   ->  vuelve al listado
       otra sección     ->  vuelve al inicio
       ya en el inicio  ->  avisa, y recién ahí sale
   Es una de esas cosas que no se notan cuando están bien, pero irritan
   muchísimo cuando faltan. */
(function(){
  if(typeof window==='undefined'||!window.history||!history.pushState)return;
  window.__apiceAtras=true;
  let avisoSalir=null;

  function sembrar(){ try{ history.pushState({apice:1},'',location.href); }catch(e){} }

  function mostrarAvisoSalir(){
    let el=document.getElementById('avisoSalir');
    if(!el){
      el=document.createElement('div');
      el.id='avisoSalir';
      el.style.cssText='position:fixed;left:50%;transform:translateX(-50%);bottom:22px;z-index:100003;'
        +'background:#1C2433;color:#fff;padding:11px 18px;border-radius:11px;font-size:13.5px;'
        +'font-family:system-ui,sans-serif;box-shadow:0 8px 26px rgba(15,20,30,.3)';
      document.body.appendChild(el);
    }
    el.textContent='Tocá "atrás" otra vez para salir de ÁPICE';
    el.style.display='block';
    clearTimeout(avisoSalir);
    avisoSalir=setTimeout(function(){ if(el)el.style.display='none'; },2200);
  }

  window.addEventListener('popstate',function(){
    let manejado=false;
    try{
      if(st && st.modal && typeof closeModal==='function'){
        closeModal(); manejado=true;
      } else if(st && st.cliente && st.cliCausa && typeof cliVerCausas==='function'){
        cliVerCausas(); manejado=true;
      } else if(st && st.vista==='ficha' && typeof cerrarFicha==='function'){
        cerrarFicha(); manejado=true;
      } else if(st && (st.nav||'dashboard')!=='dashboard' && typeof navTo==='function'){
        navTo('dashboard'); manejado=true;
      }
    }catch(e){}

    if(manejado){
      sembrar();               // seguimos capturando el próximo "atrás"
    }else{
      mostrarAvisoSalir();     // ya está en el inicio: avisa antes de salir
      sembrar();
    }
  });

  window.addEventListener('load',function(){ setTimeout(sembrar,800); });
})();

/* ===== Portal del cliente: que se entienda sin saber derecho (v46) =====
   La duda de todo cliente es siempre la misma: "¿qué pasó y qué sigue?".
   Antes tenía que deducirlo de una lista de movimientos en lenguaje jurídico.
   Ahora lo primero que ve es la última novedad en claro, y abajo cómo
   comunicarse. */
let __cliEstudio=null;

function cliUltimoHTML(sel){
  const bit=(sel&&sel.bitacora)||[];
  const arch=(sel&&sel.archivos)||[];
  const todos=bit.map(b=>({fecha:b.fecha,texto:b.texto}))
    .concat(arch.map(a=>({fecha:a.fecha_doc?fmtFechaDoc(a.fecha_doc):'',texto:'Se incorporó el documento "'+(a.nombre||'documento')+'"'})));
  todos.sort((x,y)=>(parseDMY(y.fecha)||0)-(parseDMY(x.fecha)||0));
  const u=todos[0];
  if(!u)return '<div class="cli-ultimo"><div class="cu-h">Lo último que pasó</div>'
    +'<div class="cu-txt">Todavía no hay movimientos cargados en su causa.</div></div>';
  let cuando='';
  const d=parseDMY(u.fecha);
  if(d){
    const dias=Math.floor((Date.now()-d)/86400000);
    cuando = dias<=0?'hoy':(dias===1?'ayer':('hace '+dias+' días'));
  }
  return '<div class="cli-ultimo">'
    +'<div class="cu-h">Lo último que pasó</div>'
    +'<div class="cu-txt">'+esc(u.texto)+'</div>'
    +'<div class="cu-pie">'+esc(u.fecha||'')+(cuando?(' · '+cuando):'')+'</div>'
    +'</div>';
}

/* Arma el número para el enlace de WhatsApp (v46).
   WhatsApp exige el formato internacional: sin el +, sin espacios y CON el
   código de país. Para celulares argentinos es 54 + 9 + característica + número.
   Ejemplo: 3834388918 (Catamarca) -> 5493834388918
   Se contemplan los errores de tipeo más comunes: el 0 de la característica
   y el 15 del celular, que en el formato internacional NO van. */
function waNumero(tel){
  let n=String(tel||'').replace(/[^0-9]/g,'');
  if(!n)return '';
  if(n.indexOf('54')===0)return n;   // ya viene con código de país
  if(n.indexOf('0')===0)n=n.slice(1); // sacar el 0 inicial
  n=n.replace(/^(\d{2,4})15/,'$1');   // sacar el 15 que va después de la característica
  return '549'+n;
}
function cliContactoHTML(){
  const e=__cliEstudio;
  if(!e)return '';
  const tel=(e.telefono||'').trim();
  const mail=(e.email||'').trim();
  if(!tel&&!mail)return '';
  const soloNum=waNumero(tel);
  return '<div class="cli-contacto">'
    +'<div class="cc-h">¿Tiene una consulta sobre su caso?</div>'
    +'<div class="cc-sub">Escríbanos cuando quiera. Preferimos que pregunte antes de quedarse con la duda.</div>'
    +'<div class="cc-btns">'
    +(soloNum?('<a class="cc-btn" href="https://wa.me/'+soloNum+'" target="_blank" rel="noopener">Escribir por WhatsApp</a>'):'')
    +(tel?('<a class="cc-btn sec" href="tel:'+attr(tel)+'">Llamar '+esc(tel)+'</a>'):'')
    +(mail?('<a class="cc-btn sec" href="mailto:'+attr(mail)+'">'+esc(mail)+'</a>'):'')
    +'</div></div>';
}
